INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (33,17,'1. 기계적 요인','1-4 충돌위험 부분','작업중 건설기계 오작동으로인한 차량 및 근로자 충돌',2,3,'높음','건설기계 운전자 안전교육 및 계획 수립하여 적정 신호수 배치 및 안전시설물, 차량,보행자 통제 및 미작업시 시동 끔 교육 하여 작업 시행 / 감소대책: 붐대 및 샤블 선회 반경 내 인원 통재를 위한 신호수 추가 배치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (34,17,'1. 기계적 요인','1-4 충돌위험 부분','굴착 건설기계 및 관로작업시 건물외벽, 주차차량 충돌',2,3,'높음','굴착기계 반경확보 및 주차 차량 이동으로 작업 공간 확보후 작업시행 / 감소대책: 붐대 및 샤블 선회 반경 내 인원 통재를 위한 신호수 추가 배치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (35,17,'1. 기계적 요인','1-4 충돌위험 부분','굴착 작업 종료 후 굴착구간 외부로 이동시 차량, 보행자 충돌 위험',1,3,'보통','굴착구간 외부로 이동 시 주변 상태 확인 및 신호수에 의한 차량 및 보행자 통제',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (36,17,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','정돈된 작업 공간 미확보로 작업자 걸림',3,2,'높음','작업 공간을 정리정돈하여 작업공간 확보 후 작업 / 감소대책: 아웃트리거 설치 및 고임목 설치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (37,17,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','도로내 포트홀 및 파손에 의한 작업자 걸림',3,2,'높음','작업전 포트홀 및 도로파손 확인후 보수하여 위험개소 해소 후 작업투입 / 감소대책: 위험 안내표지판 설치 및 신호수 배치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (38,17,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','경사지 굴착시 건설기계 추락 및 작업자 추락',1,3,'보통','도로 경사시 굴착시 지반확인 및 경사지 지지재 등 안전확보하여 작업시행',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (39,17,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','작업자가 굴착구간 이동에 필요한 이동식 사다리 사용시 작업자 추락',2,3,'높음','사다리를 오르내릴 때에는 한단씩 이동토록 한다. 사다리를 설치할때 사다리 펼침정도와 지면상태를 확인한다. / 감소대책: 개구부 안내표지 판 설치 및 안전난간 및 신호수 배치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (40,17,'2. 전기적 요인','2-1 감전(안전전압초과)','굴착간 노출된 전기 시설물 및 전기 누전 부분 접촉으로 인한 감전',1,3,'보통','작업구간 주변 전원 차단 후 작업 시행, 절연용 보호구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (41,17,'3. 화학적 요인','3-1 가스','아스팔트 원물 운반시 발생하는 유증기로 인한 호흡기 질환 및 중독위험',1,3,'보통','규정된 마스크 착용 및 개방된 공간에서 아스팔트 취급',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (42,17,'3. 화학적 요인','3-1 가스','작업 구간 내 가스 관로 파손으로 인한 가스 누출, 중독',1,3,'보통','작업 전 굴착신고 및 지중 매설물 유무 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (43,17,'3. 화학적 요인','3-2 증기','아스팔트 원물운반시 발생하는 고온의 유증기로 인한 호흡기 질환 위험',1,3,'보통','유증기가 발생중인 아스팔트 취급시 굴착기와 같은 장비사용(인력투입 금지)',1,2,'낮음','관리감독자',1);
