INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (46,17,'3. 화학적 요인','3-9 화재폭발위험','아스팔트 포장을 위한 피니셔 장비 사용시 피니셔 장비에 탑재되어있는 LPG 가스통이 폭발할 위험',1,3,'보통','LPG가스통 주변 화기금지, 포장작업 전/중/후 수시로 LPG가스통 및 가스라인 확인/누출점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (47,17,'5. 작업특성 요인','5-1 소음','차량계 하역운반/건설기계(굴착기) 및 작업도구(함마드릴, 코어드릴 등)의 소음에 장시간 노출되어 소음성 난청 유발 위험',1,3,'보통','주기적인 휴식시간 부여 및 소음이 잦고 큰 경우 귀마개 또는 귀덮개 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (48,17,'5. 작업특성 요인','5-3 진동','차량계 하역운반/건설기계(다짐기, 함마드릴, 코어드릴 등) 및 작업도구의 진동에 장시간 노출되어 근골격계 질환 유발 위험',2,3,'높음','작업 전 스트레칭 및 주기적인 휴식시간 부여 / 감소대책: 장기간 작업 금지 및 주기적인 휴식 보장',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (49,17,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','작업간 숙련도 부족으로 우발적 상황대처가 부족하여 발생하는 다양한 상해위험',3,1,'보통','위험도가 높은 작업의 경우 숙련자 배치 숙련자를 통한 초보인력의 사전 수준향상조치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (50,17,'5. 작업특성 요인','5-7 중량물 취급작업','인력으로 중량물 운반 작업 시 근골격계 질환 유발위험',3,2,'높음','운반용 기계기구 사용 및 작업 전 스트레칭, 주기적인 휴식시간 부여 / 감소대책: 23kg초과 물질은 기계로 양중하고 이하는 2인1조 작업',2,3,'보통','관리감독자',1);
