INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (52,17,'5. 작업특성 요인','5-9 불안정한 작업자세','인력 굴착 작업시 불안정한 작업자세로 인한 근골격계 질환 유발위험',3,2,'높음','작업 전 스트레칭 및 주기적인 휴식시간 부여, 안전한 작업공간 확보(비계, 작업발판 등) / 감소대책: 신호수 안전교육으로 작업중 작업자에게 집중하도록 지도/차량계하역기계의 붐대 움직임과 장태를 관찰',2,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (53,17,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 저온에서 작업하여 한랭질환 발생위험',3,1,'보통','보온되는 작업복 착용, 장시간 실사 지양',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (54,17,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 고온에서 작업하여 온열질환 발생위험',3,1,'보통','충분히 환기되는 작업복 착용, 장시간 실사 지양, 충분한 수분 및 염분섭취',1,2,'낮음','관리감독자',1);
