INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (83,18,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','FC관 및 내관 절단시 공구사용에 의한 베임',3,2,'높음','작업전 절단공구 안전확인 및 작업자 교육을 통한 공구사용으로 안전한 작업 시행 / 감소대책: 절단 베임 방지 장갑 지급 및 착용 지도점검',2,2,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (84,18,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','케이블 탈피시 탈피기 및 커터칼에 의한 손 베임',3,2,'높음','케이블 탈피전 탈피기 및 커너칼 날 확인하여 안전한 길이 확인 후 케이블 탈피 / 감소대책: 절단 베임 방지 장갑 지급 및 착용 지도점검',2,2,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (85,18,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','맨홀과 관로의 접속작업시 맨홀 내 날카로운 구조물(철근, 앵글 등) 등으로 작업자 신체 베임',2,3,'높음','올바른 작업복 착용으로 피부 노출을 최소화 / 감소대책: 절단 베임 방지 장갑 지급 및 착용 지도점검',2,2,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (86,18,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','시설된 관로와 전주선로의 접속작업을 위한 차량탑재형 고소작업대 사용시 연약지반, 경사로 등 불안전한 지면에서 작업 중 차량 전도위험',2,3,'높음','작업 전 연약지반 및 경사지 여부 확인 후 연약지반에서는 받침목, 아웃트리거 최대확장/ 경사지에서는 고임목, 받침목 설치 / 감소대책: 작업 시작전 장업장을 점검하여 안전작업방안 및 장애물을 제거하고 작업계획서에 반영하여 팀원간 공유',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (87,18,'1. 기계적 요인','1-4 충돌위험 부분','차량탑재형 고소작업대를 이용한 지중관로와 전주함체의 접속 또는 외선 선통시 작업자와 차량이 충돌할 위험',2,3,'높음','차량탑재형 고소작업대의 적절한  작업반경을 확보하고, 신호수 배치 및 도로교통 통제물자 배치하여 안전한 작업공간 확보 후 작업 시행 / 감소대책: 버켓차량의 붐대를 확장한 작업 반경으ㅜㄹ 설정하고 안전조치를 취한 다음 신호수 배치하여 인원의 통재',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (88,18,'1. 기계적 요인','1-4 충돌위험 부분','건설기계(크레인, 오거장비 등)의 작업 반경에 의한 차량 및 근로자 충돌',2,3,'높음','건설기계별 적절한 작업반경 확보하고, 신호수 배치 및 도로교통 통제물자 배치하여 안전한 작업공간 확보 후 관로작업 시행 / 감소대책: 버켓차량의 붐대를 확장한 작업 반경을 설정하고 안전조치를 취한 다음 신호수 배치하여 인원의 통재',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (89,18,'1. 기계적 요인','1-4 충돌위험 부분','작업중 차량탑재형 고소작업대 / 건설기계 오작동으로인한 차량 및 근로자 충돌',2,3,'높음','차량탑재형 고소작업대 / 건설기계의 운전자 안전교육 작업공간에 적합한 소요만큼 신호수 및 안전시설물 배치 차량,보행자 통제 및 미작업시 시동 끄도록 교육/확인 / 감소대책: 버켓차량의 붐대를 확장한 작업 반경을 설정하고 안전조치를 취한 다음 신호수 배치하여 인원의 통재',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (90,18,'1. 기계적 요인','1-4 충돌위험 부분','건설기계로 자재인양시 건물외벽 또는 주차차량 충돌',2,3,'높음','사전 회전반경을 고려한 건설기계 위치지정 미 작업전 주차 차량 이동으로 작업 공간 확보후 작업시행 / 감소대책: 버켓차량의 붐대를 확장한 작업 반경으ㅜㄹ 설정하고 안전조치를 취한 다음 신호수 배치하여 인원의 통재',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (91,18,'1. 기계적 요인','1-4 충돌위험 부분','차량탑재형 고소작업대 / 건설기계 사용 중 전주 등 구조물에 충돌',2,3,'높음','조작 운전원은 충분한 시야확보를 하며 이동 경로상 장애물을 주의하여 조작 / 감소대책: 운전원의 충분한 시야 확보와 신호수의 차량 통제 강화',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (92,18,'1. 기계적 요인','1-4 충돌위험 부분','맨홀 내 작업 종료 후 맨홀 외부로 이동시 차량, 보행자 충돌 위험',1,3,'보통','맨홀 외부로 이동 시 주변 상태 확인 및 신호수에 의한 차량 및 보행자 통제',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (93,18,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','정돈되지 않은 작업공간으로 인한 작업자 넘어짐',3,2,'높음','주변 작업 공간 확보하여 자재 정리후 작업투입 / 감소대책: 작업장 주변 정리정돈 및 미끄럼 방지테이프 등 미끄럼 방지 장치 성치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (94,18,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','관로작업공간의 포트홀 및 불규칙한 지면에 의한  작업자 넘어짐',3,2,'높음','작업전 포트홀 보수조치 및 불규칙한 지면의 평탄화 / 정리조치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (95,18,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','관로작업공간의 구조물에의한 작업자 이동중 넘어짐',3,2,'높음','이동경로상 지면상태 및 장애물을 확인하고 주의하며 이동한다. / 감소대책: 장애물 안내표지판 설치 및 신호수 배치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (96,18,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','차량탑재형 고소작업대 승하차 중 실족으로 인해 작업자 넘어짐',3,2,'높음','안전화 등 개인보호구 착용, 몸이 지지된 상태에서 승하차 / 감소대책: 안전화등 지급및 미끄럼방지 테이프 부착',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (97,18,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','시설된 관로와 전주선로의 접속작업을 위한 차량탑재형 고소작업대 사용 작업중 추락위험',2,3,'높음','차량탑재형 고소작업대로 작업시 조가선이나 안전고리 체결이 가능한 물체에 안전고리를 체결한 상태에서 작업 / 감소대책: 안전고리 조가선에 안전하게 체결하고 신호수의 작업자 안전 작업여부를 주의 깊게 관찰 교육',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (98,18,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','시설된 관로와 전주선로의 접속작업을 위한 차량탑재형 고소작업대 사용시 붐대상승 중 추락위험',2,3,'높음','버켓내부의 안전고리를 체결할 수 있는 물체에 안전고리를 체결한 상태에서 버켓상승조작 / 감소대책: 안전고리 조가선에 안전하게 체결하고 신호수의 작업자 안전 작업여부를 주의 깊게 관찰 교육',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (99,18,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','관로 작업에 필요한 이동식 사다리 사용시 작업자 추락',2,2,'보통','사다리를 오르내릴 때에는 한단씩 이동토록 한다. 사다리를 설치할때 사다리 펼침정도와 지면상태를 확인한다. 사다리를 작업발판으로 사용시 안전대 착용, 최상부 발판 작업 금지, 2인 1조 작업 등 의 안전조치를 수행 / 감소대책: 반드시 2인 1조 작업 원칙 및 사다리사용원칙 준수',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (100,18,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','맨홀 내 사다리 고정상태 불량/ 미설치로 인해 추락',1,2,'낮음','사다리 설치 유무 및 사다리 승하강 전 고정상태 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (101,18,'2. 전기적 요인','2-1 감전(안전전압초과)','작업공간내 전기 시설물 및 전기 누전 부분 접촉으로 인한 감전',1,3,'보통','전원 차단 후 작업 시행, 절연용 보호구 착용',1,2,'낮음','관리감독자',1);
