INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (154,19,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','작업간 숙련도 부족으로 우발적 상황대처가 부족하여 발생하는 다양한 상해위험',3,1,'보통','위험도가 높은 작업의 경우 숙련자 배치 숙련자를 통한 초보인력의 사전 수준향상조치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (155,19,'5. 작업특성 요인','5-7 중량물 취급작업','인력으로 중량물 운반 작업 시 근골격계 질환 유발위험',3,2,'높음','운반용 기계기구 사용 및 작업 전 스트레칭, 주기적인 휴식시간 부여 / 감소대책: 23kg초과 물질은 기계로 양중하고 이하는 2인1조 작업',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (156,19,'5. 작업특성 요인','5-8 반복작업','인력 천공 작업시 반복작업에 의한 근골격계 질환 유발위험',1,2,'낮음','작업 전 스트레칭 및 주기적인 휴식시간 부여',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (157,19,'5. 작업특성 요인','5-9 불안정한 작업자세','인력 천공 작업시 불안정한 작업자세로 인한 근골격계 질환 유발위험',3,2,'높음','작업 전 스트레칭 및 주기적인 휴식시간 부여, 안전한 작업공간 확보(비계, 작업발판 등) / 감소대책: 신호수 안전교육으로 작업중 작업자에게 집중하도록 지도/차량계하역기계의 붐대 움직임과 장태를 관찰',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (158,19,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 저온에서 작업하여 한랭질환 발생위험',3,1,'보통','보온되는 작업복 착용, 장시간 실사 지양',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (159,19,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 고온에서 작업하여 온열질환 발생위험',3,1,'보통','충분히 환기되는 작업복 착용, 장시간 실사 지양, 충분한 수분 및 염분섭취',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (160,19,'6. 작업환경 요인','6-2 조명','야간 작업시 부족한 조도로 인하여 작업간 각종 설비시설 및 장비 등 다양한 물체와 협착, 충돌 등 상해위험',3,1,'보통','작업환경에 맞는 조명 운영, 안전장구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (161,19,'6. 작업환경 요인','6-3 공간 및 이동통로','정리되지 않은 공간 및 이동통로로 인하여 넘어질 위험',3,2,'높음','작업장소 수시 정리정돈, 통로 확보 / 감소대책: 추가적인 신호수 배치 및 작업안전 반경 설정과 구간내로 차량 접근 금지 통제',2,3,'높음','관리감독자',1);
