INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (188,21,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','장비 외부나 철과류 등 표면 돌출 부분에 베임 및 긁힘',2,2,'보통','안전장갑 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (189,21,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','장비 탑승시 모서리 베임 또는 긁힘발생',3,1,'보통','접근금지 / 감소대책: 사람,화물 탑승시 모서리 확인 후 탐승 및 상하차 진행',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (190,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','작업 공간 자재 과중 적재로 자재 넘어짐',2,2,'보통','현장 작업공간 정리정돈 및 무리한 작업 지양',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (191,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','화물 이동시 수평 불량으로 화물 추락',2,3,'높음','차량 정차 후 수평작업 후 진행 / 감소대책: 사람. 화물 탑승시 아웃트리거 펼치고 수평 맞춰서 진행 아웃 트리거를 설치하여 작업 전 수평을 맞춘다.',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (192,21,'1. 기계적 요인','1-4 충돌위험 부분','상/하차 및 탑승 작업시 보행자와 충돌',2,2,'보통','상하차시 보행자 확인 / 감소대책: 신호수 배치 작업으로 주변 보행자를 피해서 작업 작업 준비 중 보행자 진입 통제',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (193,21,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','무리하게 자재인양하다 입구턱에 걸려 넘어지거나 헛디딤',2,2,'보통','사전 작업 위치 파악 후 작업 계획에 반영 / 감소대책: 작업 이동 공간 별로 확보하여 안전작업 진행',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (194,21,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','차량 주차시 경사지 미끄러짐',2,2,'보통','차량고임목 설치 / 감소대책: 아웃트리거, 고임목 설치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (195,21,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','개구부 주변 작업시 보행자 추락',2,2,'보통','접근금지 푯말을 설치한다. / 감소대책: 신호수 배치. 작업안내판 설치 작업 중 다른사람의 접근을 차단한다. 라바콘을 설치한다.',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (196,21,'2. 전기적 요인','2-1 감전(안전전압초과)','차량 이동중 붐대가 전주에 걸릴 경우 고압감전 발생으로 위험함',1,3,'보통','차량 운전시 붐대를 내리고 운전한다. / 감소대책: 1. 차량 붐대를 차량의 최 하단에 위치시킴 2. 이동시 붐대에 사람 탑승시 이동불가',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (197,21,'2. 전기적 요인','2-1 감전(안전전압초과)','작업 주변 전선 피복 벗겨진곳에 감전',2,3,'높음','작업 전 작업 구간내 전원선 및 전선 외부 상태 확인 후 작업 개시 / 감소대책: 작업자는 절연장갑 사용 하고 필요시 정전작업 진행한다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (198,21,'2. 전기적 요인','2-2 아크','차량 이동중 붐대가 전주에 걸릴 경우 전기적 아크 발생으로 위험함',1,3,'보통','차량 운전시 붐대를 내리고 운전한다. / 감소대책: 1. 차량 붐대를 차량의 최 하단에 위치시킴 2. 이동시 붐대에 사람 탑승시 이동불가',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (199,21,'2. 전기적 요인','3-9 화재폭발위험','기지국 및 작업공간 투입전  작업자 흡연으로 인해 화재 발생 위험',1,3,'보통','작업자는 지정된 흡연장소에서 흡연하며 화재 항시 조심하도록 교육진행한다 / 감소대책: 작업자는 불시에 일어날 화재 가능성에 작업장 근처 소화기 비치해둔다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (200,21,'2. 전기적 요인','4-3 알러지 및 미생물','꽃가루 분진으로 인한 알러지 반응',1,1,'낮음','알러지 환자 인력 관리로 작업 투입 여부 확인 후 작업 제외 / 감소대책: 알러지 약 처방 및 건강개선',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (201,21,'2. 전기적 요인','4-4 동물','작업 주변에 애완동물 물리거나 공격 당함 말벌 및 모기 등에 쏘임',1,2,'낮음','작업전 작업 주변 최초 확인후 작업 실시 / 감소대책: 강력 곤충 퇴치제로 위험요소 제거 후 작업투입',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (202,21,'5. 작업특성 요인','5-1 소음','작업 근처 소음이 심한 기계실 및  80db 이상 소음으로 인한 청력 손실',1,2,'낮음','귀마개 사용으로 청력 보호 / 감소대책: 청력손실 위험 요소 대비 하여 교육 진행',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (203,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','작업 전 위험성평가 미참여로 인한 현재 안전수칙 미숙지',3,2,'높음','근로자는 위험성평가교육 참여 (주기적 실시) / 감소대책: 작업표준미준수, 작업표준없는경우, 작업에만 과몰입, 자만심,망상',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (204,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','주의력 부족 또는 주의력 분산',2,3,'높음','근로자 자율 휴식 / 감소대책: 수면부족 또는 외부 통화등 상황을 작업전에 파악후 조치한다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (205,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','작업계획서 미작성으로 인한 주의력 분산',2,2,'보통','작업계획서 상시 작성 / 감소대책: 1. 작업계획서 상시 작성 2. 작업계획서 차량 비치 3. 현장 안전점검시 작업계획서 내용과 현장 작업자가 맞는지 확인',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (206,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','무자격자 작업으로 인해 조종불량으로 사고위험',2,2,'보통','자격여부 작업전 확인 / 감소대책: 1. 안전인증평가에 통과한 업체만 사용 2. 정기 교육 및 차량 검사를 받은 차량만 사용 3. 보험 가입여부 확인하여 사고시 충분한 보상이 되는지 확인',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (207,21,'5. 작업특성 요인','5-5 저압 또는 고압','작업공간 인근 고압변압기 존재로 작업자 감전 및 쇼크',1,3,'보통','활선접근경보기 착용하고 검전기 사용 / 감소대책: 특별안전보건 교육 실시 (전압 75V 정전 및 활선)',1,2,'낮음','관리감독자',1);
