INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (210,21,'5. 작업특성 요인','5-7 중량물 취급작업','긴시간 한곳을 응시하여 잡생각이 들면 충돌발생',3,3,'매우높음','사고 위험을 근로자가 확인 / 감소대책: 잡생각 없이 일에 집중하고 작업전 금주',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (211,21,'5. 작업특성 요인','5-7 중량물 취급작업','전주작업시 장비를 함체에 고정할 때 오랫동안 같은 자세로 작업하여 사람이나 장비의 추락사고 위험이 있슴',2,3,'높음','작업계획을 세워서 중량물을 드는 시간을 최소로 한다. / 감소대책: 1. 작업자 1인이 계속 중량물을 들지 않고 교대로 들 수있도록 한다. 2. 힘에 부치지 않게 중량물 드는 시간을 최소로 한다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (212,21,'5. 작업특성 요인','5-8 반복작업','긴시간 서서 작업시 생기는 불안정한 자세',2,2,'보통','사고 위험을 근로자가 확인 / 감소대책: 체력상 문제가 없는지 체크 및 휴식',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (213,21,'5. 작업특성 요인','5-8 반복작업','자재(블록 및 철과류 등) 반복 운반으로 허리 및 신체부상',3,2,'높음','2인1조 나눠들기 도입 및 무리한 작업 지양 / 감소대책: 중장비 (고소작업대,사다리차) 사용 하여 작업자 체력 부하방지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (214,21,'5. 작업특성 요인','5-9 불안정한 작업자세','손떨림',3,3,'매우높음','작업전 근로자 상태 확인 후 이상시 작업중지',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (215,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','미세먼지 2.5 μm 이하 작업으로 호흡계 질환 발생',2,2,'보통','마스크 지급으로 작업자 호흡계 질환 보호 / 감소대책: KF80 이상의 마스크 지급 및 호흡계 질환 환자 작업 투입 관리',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (216,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','10m/s 이상 강풍 작업으로 작업다 넘어지거나 자재 날아감으로 다침',1,2,'낮음','작업 전 풍속 확인 후 작업 투입 유무 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (217,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','한랭으로 인한 작업자 동상 및 저체온증 발생',3,2,'높음','방한화, 방한복,핫팩 등 방한용품 사용으로 인한 핸랭질환 방지 / 감소대책: 10월~4월에 다음 중 하나에 해당하는 경우 ① 아침최저기온이 전날보다 10℃ 이상 하강하여 3℃ 이하이고 평년값보다 3℃가 낮을 것으로 예상될때 ② 아침최저기온이 -12℃ 이하가 2일 이상 지속될 것이 예상될 때 ③ 급격한 저온현상으로 중대한 피해가 예상될 때',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (218,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','우천으로 인해 야외작업자 저체온증 및 전기관련 감전',1,2,'낮음','전열장갑 사용 및 우천작업 지양 / 감소대책: 적은 강수량이여도 절대 작업 금지 지향',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (219,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','폭염으로 인한 작업자 쓰러짐',3,2,'높음','포도당 및 충분한 휴식 작업안전 가이드 안내 / 감소대책: 폭염으로 인하여 다음 중 어느 하나에 해당하는 경우 ① 일최고체감온도 33℃이상인 상태가 2일 이상 지속될 것으로 예상될 때 ② 급격한 체감온도 상승 또는 폭염 장기화 등으로 중대한 피해발생이 예상될 때',1,2,'낮음','관리감독자',1);
