INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (232,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','굴삭기로 인얀작업 시 1줄걸이 사용중 요동에 의한 충돌, 낙하',2,2,'보통','자재양중 작업 시 2줄걸이 등으로 안전한 결속',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (233,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','굴삭기 작업중 버켓이 탈락되어 낙하',2,2,'보통','연결부 등의 이상유무를 사전 점검하고 작업 실시',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (234,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','정격하중을 넘어선 중량물 인양으로 작업차량 전도',2,2,'보통','차량 불법개조 하지며 정격하중을 고려하여 작업한다',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (235,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','화물 이동시 수평 불량으로 화물 추락',3,3,'매우높음','차량 정차 후 수평작업 후 진행 / 감소대책: 사람. 화물 탑승시 아웃트리거 펼치고 수평 맞춰서 진행',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (236,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','스카이차 탑승시 스카이차 붐대 절단으로 인한 낙하사고',2,3,'높음','붐대가 지탱하는 무게를 감안하여 작업자탑승 및 화물운송 / 감소대책: 1. 붐대가 지탱하는 무게를 감안하여 화물 운송 2. 차량이 하중을 지지 할 수 있도록 가능한 정면이나 후면으로 붐대를 뻗칠 수 있도록 한다. 3. 붐대가 측면으로 뻗어야 하는 장소는 아웃트리거 받침대를 넓은 걸 사용하여 하중이 분산되도록 한다.',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (237,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','1줄걸이(1점)지지로 양중중 낙하, 이종규격 인양로프 사용하여 양종중 로프파단 등으로 낙하',2,3,'높음','2점이상 결속하여 인양 동일규격의 인양로프 사용 / 감소대책: 2점이상 결속하여 인양 동일규격의 인양로프 사용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (238,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','슬링밸트 사용시 샤클볼트 부분을 위로 향하게 체결하여 작업 중 샤클풀림으로 낙하',2,3,'높음','샤클 부분의 볼트부분이 아래쪽으로 향하게 체결(풀림방지) / 감소대책: 샤클 부분의 볼트부분이 아래쪽으로 향하게 체결(풀림방지)',2,3,'높음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (239,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','고소작업차량 아웃트리거 설치 상태 불량으로 인한 차량 전도',2,3,'높음','아웃트리거 최대로 설치 하고 고임목 안전하게 설치 / 감소대책: 아웃트리거 최대 전개 및 고임목 설치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (240,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','인양소켓 단말 가공처리 미흡, 클립  풀림에 의한 자재낙하재해',2,3,'높음','와이어로프 단선에 클립체결, 와이어로프 단선에 와이어로프 덧댐 후 클립 체결 / 감소대책: 2점이상 결속하여 인양 동일규격의 인양로프 사용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (241,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','작업 전 불량한 지반에 아웃트리거 설치로  작업중 편심이 발생하여 작업 차량 넘어짐',2,3,'높음','작업 전 지반 상태 확인 및 고임목은 아웃트리거 발판 기준에 맞게 설치한다 / 감소대책: 아웃트리거 최대 전개 및 고임목 설치',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (242,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','정격하중을 넘어선 중량물 인양으로 작업차량 전도',2,3,'높음','작업차량 불법개조 금지, 정격하중을 고려하여 작업한다 / 감소대책: 과도한 적제 금지 및 아웃트리거, 받침목 등 설치로 전도방지',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (243,21,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','작업자가 사다리차 운반물 상부에 탈 경우 추락 위험',2,3,'높음','작업자가 작업중 운반수레에 타는 것 금지 / 감소대책: 1. 작업전 안전교육 및 TBM 활동 2. 붐대의 운반차에 작업자 탑승시 즉시 작동 중지',1,1,'낮음','관리감독자',1);
