INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (248,21,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','개구부 주변 작업시 보행자 추락',3,3,'매우높음','접근금지 / 감소대책: 신호수 배치. 작업안내판 설치',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (249,21,'2. 전기적 요인','2-1 감전(안전전압초과)','건물이나 전주 전선에 걸려서 쇼트로 인한 감전',3,3,'매우높음','개인작업으로 작업자가 확인 / 감소대책: 신호수 배치 작업으로 주변 전선을 피해서 작업',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (250,21,'2. 전기적 요인','2-1 감전(안전전압초과)','차량 외부 벗겨진 피복에 감전',1,3,'보통','작업 전 작업 구간내 전원선 및 전선 외부 상태 확인 후 작업 개시 / 감소대책: 충전전로의 인근 작업시에는 산업안전보건기준에 관한 규칙 제322조(충전전로 인근에서의 차량․기계장치 작업) 규정에 따라 고소작업대를 충전전로의 충전부로부터 충분한 이격거리를 유지하였는지를 확인',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (251,21,'2. 전기적 요인','2-1 감전(안전전압초과)','인양작업장 주변 고압선로에 접촉 감전',1,3,'보통','작업전 작업장 주변 지상 및 지하 지장물 현황을 확인하고 작업',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (252,21,'2. 전기적 요인','2-2 아크','버켓이 전주에 걸려서 22천V단선시 아크발생 아크 발생과 감전이 동시 발생',2,3,'보통','가능한한 빨리 사고 현장에서 떨어진다.활선경보기 착용 / 감소대책: 1. 전주에서 1M 이상 떨어진다. 2. 버켓조정시 감전이 안되도록 조심한다. 3. 활선경보기를 상시 착용한다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (253,21,'2. 전기적 요인','3-9 화재폭발위험','작업중 휴식 간 작업자 흡연으로 인해 화재 발생 위험',2,2,'보통','작업자는 지정된 흡연장소에서 흡연하며 화재 항시 조심하도록 교육진행한다 / 감소대책: 흡연금지 및 소화기 배치',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (254,21,'2. 전기적 요인','3-10 복사열, 폭발과압','복사열에 취약한 라이타 , 스프레이등 외부 노출시킴에 폭발',1,3,'보통','복사열에 취약한 라이타 , 스프레이등 반입 금지 및 임시보관장소 보관',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (255,21,'4. 생물학적 요인','4-1 병원성 미생물, 바이러스에        의한 감염','외부 작업시 봄/가을 바이러스나 미생물에 의한 오염으로 작업자 건강상태 위험',1,2,'낮음','들판이나 산에서 바닥에 앉을 경우 주의한다. / 감소대책: 1. 산.들에서 바닥에 바로 앉지 않고 천이나 매트 등을 이용한다. 2. 작업이 끝난 후에는 손과 발을 깨끗이 씻는다.',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (256,21,'4. 생물학적 요인','4-3 알러지 및 미생물','꽃가루 분진으로 인한 알러지 반응',1,2,'낮음','알러지 환자 인력 관리로 작업 투입 여부 확인 후 작업 제외',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (257,21,'4. 생물학적 요인','4-4 동물','작업 주변에 애완동물 물리거나 공격 당함 말벌 및 모기 등에 쏘임',1,2,'낮음','작업전 작업 주변 최초 확인후 작업 실시',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (258,21,'4. 생물학적 요인','4-4 동물','하절기 말벌 공격',2,3,'높음','방충모자, 방충토시 착용 및 벌레 퇴치제 등을 활용 / 감소대책: 1. 향이 짙은 향수 및 화장품 등 사용 자제 2. 집을 건드렸을 때는 팔을 휘두르는 등 몸짓을 크게 하지 말고 머리를 감싼 채 20m 이상 떨어진 곳으로 피함',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (259,21,'5. 작업특성 요인','5-1 소음','작업 근처 소음이 심한 기계실 및 80db 이상 소음으로 인한 청력 손실',1,2,'낮음','귀마개 지급',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (260,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','주의력 부족 또는 주의력 분산',2,4,'매우높음','근로자 자율 휴식 / 감소대책: 수면부족 또는 외부 통화등 상황을 작업전에 파악후 조치한다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (261,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','장비 작업계획 수립 미흡으로 인한 안전사고',2,2,'보통','장비 작업전 작업계획을 수립/검토/승인 후 작업실시 / 감소대책: 작업계획 작성 및 주기적인 장비 점검 실',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (262,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','장비전문가의 점검 등 미흡으로 인한 사고',2,2,'보통','주기적으로 장비전문가를 통한 점검 실시 / 감소대책: 작업계획 작성 및 주기적인 장비 점검 실',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (263,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','후크해지 장치 불량으로 인한 낙하',2,3,'높음','후크해지 장치 사용중 수시점검, 인양초기 관리 철저 / 감소대책: 후크 상태 주기적 점검 및 작업안전가이드 준수 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (264,21,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','조종수 휴먼에러로 인한 조작실수로 근로자 다침',2,3,'높음','조종수는 안전교육 이수하며 작업에 집중한다 / 감소대책: 조종수 안전교육 이수 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (265,21,'5. 작업특성 요인','5-5 저압 또는 고압','작업 공간 인근 고압변압기 및 전선 존재로 작업자 감전 및 쇼크',2,3,'높음','조종수는 안전교육 이수하며 작업에 집중한다 / 감소대책: 조종수 안전교육 이수 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (266,21,'5. 작업특성 요인','5-7 중량물 취급작업','중량물 취급 중 낙하',3,3,'매우높음','사고 위험을 근로자가 확인 / 감소대책: 중량물 취급시 작업절차 준수하여 중량물 낙하방지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (267,21,'5. 작업특성 요인','5-7 중량물 취급작업','시브 표면의 부식 손상에 따른 와이어 파단으로  이어지는 사고(로프 이탈방지장치 미설치)',1,4,'보통','무부하상태에서 회전 소모상태, 유격 등  확인 철저 및 소모성 부품 적기 교체 준수 (시브에 로프 이탈방지장치 설치) / 감소대책: 과도한 중량물 적제 금지 및 중량물 작업안전 가이드 준수',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (268,21,'5. 작업특성 요인','5-7 중량물 취급작업','정격하중 이상 중량물 인양으로 인해 차량 전도',2,3,'높음','작업차량 불법개조 금지, 정격하중을 고려하여 작업한다 / 감소대책: 과도한 중량물 적제 금지 및 중량물 작업안전 가이드 준수',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (269,21,'5. 작업특성 요인','5-7 중량물 취급작업','긴시간 한곳을 응시하여 잡생각이 들면 충돌발생',3,3,'매우높음','사고 위험을 근로자가 확인 / 감소대책: 잡생각 없이 일에 집중하고 작업전 금주',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (270,21,'5. 작업특성 요인','5-8 반복작업','긴시간 서서 작업시 생기는 불안정한 자세',2,2,'보통','사고 위험을 근로자가 확인 / 감소대책: 체력상 문제가 없는지 체크 및 휴식',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (271,21,'5. 작업특성 요인','5-9 불안정한 작업자세','신호수가 전화를 받거나 한눈을 팔아서 사고위험발생',2,3,'보통','1. 작업중 신호수는 전화금지 / 감소대책: 1. 신호수 안전교육으로 작업전 작업자에게 집중 2. 차량하역기계의 붐대 움직음과 작업자 상태를 관찰하도록 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (272,21,'5. 작업특성 요인','5-10 작업(조작)도구','조종수 조작도구 불량으로 인해 오작동으로 인한 작업차량 결함',1,3,'보통','조종수는 안전교육 이수하며 작업에 집중한다',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (273,21,'5. 작업특성 요인','5-10 작업(조작)도구','스페너나 해머 망치등을 사용시 손다침 위험',2,3,'높음','작업시 주의 / 감소대책: 1. 작업자가 베임방지 안전장갑 착용 2. 작업자가 한눈 팔지 않고 집중할 수 있도록 주변에서 도와준다.',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (274,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','미세먼지 2.5 μm 이하 작업으로 호흡계 질환 발생',1,2,'낮음','마스크 지급으로 작업자 호흡계 질환 보호',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (275,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','강풍으로 인한 붐대 영향으로 고소차량 전도',3,2,'높음','작업 전 풍속 확인 후 작업 투입 유무 확인 / 감소대책: 비, 눈, 그 밖의 기상상태의 불안정으로 날씨가 몹시 나쁜 경우에는 산업안전보건기준에 관한 규칙 제37조(악천후 및 강풍 시 작업중지) 또는 제383조(작업의 제한) 의 기준을 준용하여야 한다.',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (276,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','한랭으로 인한 작업자 동상 및 저체온증 발생',2,2,'보통','방한화, 방한복,핫팩 등 방한용품 사용으로 인한 핸랭질환 방지 / 감소대책: 10월~4월에 다음 중 하나에 해당하는 경우 ① 아침최저기온이 전날보다 10℃ 이상 하강하여 3℃ 이하이고 평년값보다 3℃가 낮을 것으로 예상될때 ② 아침최저기온이 -12℃ 이하가 2일 이상 지속될 것이 예상될 때 ③ 급격한 저온현상으로 중대한 피해가 예상될 때',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (277,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','우천으로 인해 야외작업자 저체온증 및 전기관련 감전',2,2,'보통','전열장갑 사용 및 우천작업 지양 / 감소대책: 적은 강수량이여도 절대 작업 금지 지향',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (278,21,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','폭염으로 인한 작업자 쓰러짐',2,2,'보통','포도당 및 충분한 휴식 작업안전 가이드 안내 / 감소대책: 폭염으로 인하여 다음 중 어느 하나에 해당하는 경우 ① 일최고체감온도 33℃이상인 상태가 2일 이상 지속될 것으로 예상될 때 ② 급격한 체감온도 상승 또는 폭염 장기화 등으로 중대한 피해발생이 예상될 때',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (279,21,'6. 작업환경 요인','6-3 공간 및 이동통로','작업 주변 차량 및 행인 부딪힘',2,3,'높음','신호수 배치로 작업 주변 통제 / 감소대책: 1. 교통량이 많은 구간 또는 인원 통행이 많은 구간에 대해서는 추가적인 신호수 배치 또는 작업안전 반경 설정하 구간내로 차량 및 인원 접근근지 통제 3. 연약지반에 고소작업대를 설치할 때는 충분한 지지력을 확보 및 전도 방지를 위한 조치를 하고 아웃트리거는 타이어가 지면에서 뜨도록 설치 3. 작업대를 가장 낮게 하강하여 이동하여야 한다 4. 작업대가 상승한 상태에서 근로자를 태우고 이동하지 않도록 하여야 한다. 4. 이동 시 통로의 요철상태 및 장애물의 유무를 확인한 후 전도 등의 위험 방지를 위하여 유도자를 배치하고, 운전자는 전방 시야가 확보된 상태로 유도자의 지시에 따라 이동하여야 한다.',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (280,21,'6. 작업환경 요인','6-3 공간 및 이동통로','스카이 이동시 또는 암 이동시 전주나 건물 부딫힘',3,3,'매우높음','사고 위험을 근로자가 확인 / 감소대책: 1.회전 반경내 신호수 배치 후 작업 2.작업자도 스카이 기사에게 정확한 이동경로 안내 3.스카이 회전 요청시 큰소리로 잘 들리게 요청 4.스카이 기사는 미리 현장 상황을 숙지한다.',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (281,21,'6. 작업환경 요인','6-4 주변 근로자','2시간 이상 작업시 근로자 피로도 누적',3,3,'매우높음','사고 위험을 근로자가 확인 / 감소대책: 작업 중 2시간마다 10분 휴식',1,2,'낮음','관리감독자',1);
