INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (346,23,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','현장 이동시 벽이나 튀어나온 기존 구조물에 긁힘/베임',1,2,'낮음','① 안전보호구를 착용 ② 조도가 확보된 상태에서 이동하며, 이동 중 주위 돌출부위 등 위험요소를 확인하며 이동',1,2,'낮음','관리감독자',1);
