INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (348,23,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대 공구함체 등을 밟고 자재하차, 승하차 시 미끄러짐',2,2,'보통','① 안전보호구를 착용 ② 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 미끄럼 방지 테이프 부착 및 2인1조 작업 시행',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (349,23,'1. 기계적 요인','16 추락위험 부분(개구부 등)','건물  고정사다리로 승하강시 추락',1,3,'보통','① 안전보호구 착용 ② 고정사다리 상태를 확인(녹슴,볼트풀림,파손여부,흔들림 등)후 승하강 ③ 승하강시 안전고리를 사다리 발판에 체결하면서 이동',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (350,23,'2. 전기적 요인','21 감전(안전전압초과)','고소작업차에서 발생되는 누설전류로 인한 감전사고 위험',1,2,'낮음','① 활선경보기 착용 및 검전기로 누설전류 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (351,23,'6. 작업환경 요인','61 기후/고온/한랭/공기질','비, 눈, 바람 등 기상상황 중 야외 이동/작업 시 미끄러짐',2,2,'보통','① 이동경로에 바닥상태(결빙, 물 등) 확인 및 미끄럼방지조치 실시 ② 위험경보 시 옥내작업 위주로 실시, 무리한 옥외작업 금지 / 감소대책: 기상악화시 야외작업 금지',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (352,23,'1. 기계적 요인','11 협착위험 부분(감김, 끼임)','고소작업대 탑승하여 승하강 작업 시 탑승기 위에 위치한 기존 구조물 및 가로수 등에 머리가 끼임',2,2,'보통','① 안전보호구 착용 ② 기존 구조물과 가로수등의 위치를 파악하고 충분한 공간을 확보한 후 승하강 작업 ③ 승하강 작업에 협착위험이 있을 시 신호수가 작업자에게 경고 신호를 함 ③ 감독관 및 건물주와 협의하여 가능하면 장비위치를 장애물이 없는  위치로 선정 / 감소대책: 안전보호구 지급 및 착용 점검, 작업 시작전 작업점 상황 점검 및 안전조치를 강구하고 작업계획서 반영 및 팀원간공유',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (353,23,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','케이블 절단 및 커넥터 연결시, 케이블에 손 찔림',1,2,'낮음','① 안전보호구 착용(절단방지장갑 및 팔토시 착용)으로 베날카로운 노출부에 의한 사고 예방',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (354,23,'1. 기계적 요인','13 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','경사로나 주차된 차량/장애물등때문이거나 이동하면서 작업을 하기 위해서 고소작업대 아웃트리거를 설치하지 않고 붐대를 펼칠 시 무게중심이 한쪽으로 쏠려 전도 위험',2,3,'높음','① 작업전 아웃트리거 센서 정상작동 상태 확인 ② 월별 고소작업대 정기정검 (아웃트리거 센서) ③ 신호수(보조작업자)가 작업 전 아웃트리거 설치상태 재확인 ④ 교육 및 불시점검을 통해서 이동하면서 케이블 포설/철거 작업 금지 / 감소대책: 아웃트리거 센서 정기적 점검 및 안전조치 및 신호수의 역할로 아웃트리거 균형 상태 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (355,23,'1. 기계적 요인','14 충돌위험 부분','고소작업대 작업 시 주행차량에 의한 충돌',2,3,'높음','① 표지판,라바콘,에어로봇을 설치하고 신호수를 추가 배치하여 주행 차량을 통제함 ② 표지판,라바콘,에어로봇을 충분히 이격하여 설치해서 운전자가 공사중임을 미리 인지할 수 있도록 함 ③ 주행자량이 지나갈 수 있는 공간을 확보하도록 고소작업대를 설치함 / 감소대책: 공사안내표지판 및 라바콘 등으로 차량이동 통제, 신호수의 안전한 장소 위치하여 신호 통제',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (356,23,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대 자재 하차시 공구함체를 밟다가 미끄러짐',2,2,'보통','① 안전보호구를 착용하고 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 안전보호구 성능 점검과 미끄럼 방지 테이프 부착',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (357,23,'1. 기계적 요인','16 추락위험 부분(개구부 등)','고소작업대 승하강 및 고소작업 시 작업대 바깥쪽으로 신체를 과하게 내밀고 작업 중 추락',2,3,'높음','① 안전보호구 착용 ② 탑승기 승하강시 탑승기에 안전고리를 체결하고,고소작업 시 조가선 및 구조물에 안전고리 체결 ③ 신체를 과하게  바깥으로 내밀지 않도록 탑승기나 붐대 위치를 조정하여 작업함 / 감소대책: 작업 시작전에 차량정차 및 승하차 시 안전 작업원칙을 정하여 작업계획서에 반영하고 안전고리 및 안전장비 체결 점검',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (358,23,'2. 전기적 요인','21 감전(안전전압초과)','고소작업대  작업시 주변 변압기 접촉에 의한 감전',2,3,'높음','① 안전보호구 착용(활선감지기) ② 작업 전에 변압기 위치를 확인하고 안전한 작업위치를 선정하여 작업 ③ 가능하면 변압기등 고압장비가 없는 위치로 설치되도록 감독관과 협의하여 작업 위치 변경 ④ 신호수는 작업자가 감전위험이 있는 위험한 위치로 움직이면 경고 신호를 보냄',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (359,23,'2. 전기적 요인','39 화재폭발위험','UPS 활선작업 시 아크 발생으로 화재',1,3,'보통','① 인화성 물질을 제거하여 화재 예방 ② 소화기 비치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (360,23,'2. 전기적 요인','44 동물','하절기 야외 작업 중  벌쏘임',2,2,'보통','① 안전작업 절차 준수(작업반경 내 벌집 유무 확인)  ② 향이 짙은 향수 및 화장품 등 사용 자제  ③ 방충모자, 방추토시 착용 및 벌레 퇴치제 등을 활용  ④ 벌집을 건드렸을 때는 팔을 휘두르는 등 몸짓을 크게 하지 말고 머리를 감싼 채 20m이상 떨어진 곳으로 피함 / 감소대책: 벌 퇴치용 스프레이 지급 및 함체를 열기전에 내부 상황을 눈과 귀등 오감으로 파악 작업',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (361,23,'2. 전기적 요인','53 진동','전동드라이버 사용으로 인한 근골격계 질환 주의',1,2,'낮음','① 작업 전스트레칭 실시 ② 작업 중 충분한 휴식',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (362,23,'2. 전기적 요인','54 근로자실수(휴먼에러)','안전가이드 미준수 및  주의력 결핍으로 인한 안전사고 발생',2,3,'높음','① 반복적인 안전가이드 교육 및 불시 안전점검 ② 작업 중 충분한 휴식을 취하여 주의력 확보 / 감소대책: 작업안전가이드 준수 및 현장 점검 강화',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (363,23,'2. 전기적 요인','56 질식위험, 산소결핍','맨홀작업시 산소결핍에 의한 질식',2,3,'높음','① 안전보호구 착용 ② 환기팬으로 맨홀 내부 환기 ③  맨홀내부를 가스농도측정기로 측정하여 규정된 수치 이내에서만 맨홀 진입 ④ 구조용 삼각대를 설치하고 안전고리 체결 후 맨홀 진입 ⑤ 질식위험표지판,라바콘,콘걸이대 설치 ⑥ 감시인은 맨홀내부 작업자 상태가 어떤지 주기적으로 감시함 / 감소대책: 안전보호구 착용 및 작업전 산소 농도 측정, 환기및 구조 원칙 교육 및 감독',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (364,23,'2. 전기적 요인','57 중량물 취급작업','사다리차,고소작업대로,자재 운반 시 낙하물 발생',1,3,'보통','① 안전보호구 착용 ② 밧줄등으로 견고하게 고정하고 운반 ③ 표지판,라바콘을 설치하여 출입 통제 조치 ④ 신호수를 배치하여 보행자를 안전하게 유도',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (365,23,'2. 전기적 요인','58 반복작업','반복되는 작업으로 근골격계 질환 발생',2,2,'보통','작업전 스트레칭 실시  무리한 작업은 금하고 작업중에 충분한 휴식을 취함 / 감소대책: 무거운 물건은 반드시 공구를 사용하여 들고 충분한 휴식과 스트레칭 실시',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (366,23,'2. 전기적 요인','59 불안정한 작업자세','불안정하고 무리한 작업으로 근골격계 질환 발생',1,2,'낮음','① 작업전 스트레칭 실시 ② 적절한 자세로 무리하지 않도록 작업 함 ③ 작업 중 충분한 휴식을 취함',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (367,23,'2. 전기적 요인','510 작업(조작)도구','작업공구 취급 중 베임 및 찔림',2,1,'낮음','① 안전장갑(베임방지장갑), 긴팔 및 토시등 안전장구류 및 올바른 작업복 착용하여 피부 노출을 최소화',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (368,23,'6. 작업환경 요인','61 기후/고온/한랭/공기질','비,눈,안개,강풍등 악천후에 야외작업 시 미끄럽고 시야가 가려져 사고 발생',2,2,'보통','① 작업 중 충분한 휴식을 취함 ② 무리한 작업은 금지 ③위험경보 시 옥내작업 위주로 실시 / 감소대책: 무리한 야외 작업 금지',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (369,23,'6. 작업환경 요인','62 조명','맨홀안 작업시, 조도 미확보로 인한 시야 가림(부딪침, 찔림, 걸림)',1,2,'낮음','① 랜턴등의 조명으로 조도 확보',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (370,23,'6. 작업환경 요인','63 공간 및 이동통로','보행자 통로 미확보로 인한 사고 위험',1,2,'낮음','① 보행자 통로 확보 후 신호수의 보행자 유도',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (371,23,'6. 작업환경 요인','64 주변 근로자','보조작업자 및 신호수의 부주의로 인한 보행자 충돌',1,2,'낮음','① 안전 시설물(라바콘,콘 걸이대,콘라이트) 설치 ② 작업자/보조작업자간의 크로스체크',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (372,23,'6. 작업환경 요인','65 작업시간','8시간 이상 과도한 작업 진행으로 근골격게 질환 발생',1,2,'낮음','① 각 작업팀에게 적절한 작업을 배분하고 무리한 작업 금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (373,23,'6. 작업환경 요인','66 조직 안전문화','형식적이고 주먹구구식 안전관리로 인한 미흡한 안전활동으로 중대재해 발생',2,3,'높음','① 안전관리를 시스템화 하고  ② 전직원이 참여하도록 하는 KOSHA-MS / ISO45001 인증을 받고 ③ 실질적인 현장적용을 통하여 중대재해 방지 / 감소대책: 작업안전기이드 및 안전관리 시스템 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (374,24,'1. 기계적 요인','11 협착위험 부분(감김, 끼임)','옥상 출입문등이 덮개형태일 경우 덮개를 여닫는중 손 끼임',1,2,'낮음','① 안전보호구 착용 ② 덮개를 여닫을시 설치된 손잡이를 사용하고 덮개가 완전히 열렸는지 확인 후 이동한다 ③ 계속해서 덮개를 통해 이동시에는 덮개를 열란 상태로 밧줄등으로 고정한다 ④ 사다리에 매달린채 덮개를 여닫을시에는 안전고리를 견고한 구조물(사다리 발판 최상단)에 체결한 후 덮개를 개폐한다',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (375,24,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','현장 이동시 벽이나 튀어나온 기존 구조물에 긁힘/베임',1,2,'낮음','① 안전보호구를 착용 ② 조도가 확보된 상태에서 이동하며, 이동 중 주위 돌출부위 등 위험요소를 확인하며 이동',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (376,24,'1. 기계적 요인','14 충돌위험 부분','동절기 작업장 이동시, 블랙아이스 도로로 주행 시 미끄러짐으로 인한 충돌',1,2,'낮음','① 평소보다 절반가량 서행 ② 급출발, 급가속, 급제동, 급회전 금지 ③ 적정 타이어 공기압 유지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (377,24,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대 공구함체 등을 밟고 자재하차, 승하차 시 미끄러짐',2,2,'보통','① 안전보호구를 착용 ② 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 안전보후구 착용 및 미끄럼 망지테이프 부착',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (378,24,'1. 기계적 요인','16 추락위험 부분(개구부 등)','건물  고정사다리로 승하강시 추락',1,3,'보통','① 안전보호구 착용 ② 고정사다리 상태를 확인(녹슴,볼트풀림,파손여부,흔들림 등)후 승하강 ③ 승하강시 안전고리를 사다리 발판에 체결하면서 이동',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (379,24,'2. 전기적 요인','21 감전(안전전압초과)','고소작업차에서 발생되는 누설전류로 인한 감전사고 위험',1,2,'낮음','① 활선경보기 착용 및 검전기로 누설전류 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (380,24,'2. 전기적 요인','57 중량물 취급작업','자재, 공구 등 상 · 하역 작업 중 무리한 힘의 사용으로 근골격계 질환 발생',2,2,'보통','① 작업 전 스트레칭 실시  ② 중량물 상 하역시 동료 근로자와 나눠들기 또는 장비 등을 활용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (381,24,'6. 작업환경 요인','61 기후/고온/한랭/공기질','비, 눈, 바람 등 기상상황 중 야외 이동/작업 시 미끄러짐',2,2,'보통','① 이동경로에 바닥상태(결빙, 물 등) 확인 및 미끄럼방지조치 실시 ② 위험경보 시 옥내작업 위주로 실시, 무리한 옥외작업 금지 / 감소대책: 무리한 야외 작업 금지',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (382,24,'1. 기계적 요인','11 협착위험 부분(감김, 끼임)','고소작업대 탑승하여 승하강 작업 시 탑승기 위에 위치한 기존 구조물 및 가로수 등에 머리가 끼임',2,2,'보통','① 안전보호구 착용 ② 기존 구조물과 가로수등의 위치를 파악하고 충분한 공간을 확보한 후 승하강 작업 ③ 승하강 작업에 협착위험이 있을 시 신호수가 작업자에게 경고 신호를 함 ③ 감독관 및 건물주와 협의하여 가능하면 장비위치를 장애물이 없는  위치로 선정 / 감소대책: 작업 시작전 작업점 점검하여 안전작업 방안을 마련하고 작업계획서에 반영하고 위험요소를 팀원간 공유함\',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (383,24,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','케이블 절단 및 커넥터 연결시, 케이블에 손 찔림',1,2,'낮음','① 안전보호구 착용(절단방지장갑 및 팔토시 착용)으로 베날카로운 노출부에 의한 사고 예방',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (384,24,'1. 기계적 요인','13 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','경사로나 주차된 차량/장애물등때문이거나 이동하면서 작업을 하기 위해서 고소작업대 아웃트리거를 설치하지 않고 붐대를 펼칠 시 무게중심이 한쪽으로 쏠려 전도',2,3,'높음','① 작업전 아웃트리거 센서 정상작동 상태 확인 ② 월별 고소작업대 정기정검 (아웃트리거 센서) ③ 신호수(보조작업자)가 작업 전 아웃트리거 설치상태 재확인 ④ 교육 및 불시점검을 통해서 이동하면서 케이블 포설/철거 작업 금지 / 감소대책: 정기적인 아웃트리거 센서 작동 확인 및 조치 신호수에 대한 아웃트리거 상태 관점 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (385,24,'1. 기계적 요인','14 충돌위험 부분','고소작업대 작업 시 주행차량에 의한 충돌',2,3,'높음','① 표지판,라바콘,에어로봇을 설치하고 신호수를 추가 배치하여 주행 차량을 통제함 ② 표지판,라바콘,에어로봇을 충분히 이격하여 설치해서 운전자가 공사중임을 미리 인지할 수 있도록 함 ③ 주행자량이 지나갈 수 있는 공간을 확보하도록 고소작업대를 설치함 / 감소대책: 공사안내표지판 및 라바콘 등으로 차량이동 통제, 신호수의 안전한 장소 위치하여 신호 통제',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (386,24,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대 자재 하차시 공구함체를 밟다가 미끄러짐',2,2,'보통','① 안전보호구를 착용하고 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 안전보호구 성능 점검과 미끄럼 방지 테이프 부착',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (387,24,'1. 기계적 요인','16 추락위험 부분(개구부 등)','고소작업대 승하강 및 고소작업 시 작업대 바깥쪽으로 신체를 과하게 내밀고 작업 중 추락',2,3,'높음','① 안전보호구 착용 ② 탑승기 승하강시 탑승기에 안전고리를 체결하고,고소작업 시 조가선 및 구조물에 안전고리 체결 ③ 신체를 과하게  바깥으로 내밀지 않도록 탑승기나 붐대 위치를 조정하여 작업함 / 감소대책: 작업 시작전에 차량정차 및 승하차 시 안전점검 및 작업원칙을 정하여 작업계획서에 반영하고 안전고리 및 안전장비 체결 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (388,24,'2. 전기적 요인','21 감전(안전전압초과)','고소작업대  작업시 주변 변압기 접촉에 의한 감전',2,3,'높음','① 안전보호구 착용(활선감지기) ② 작업 전에 변압기 위치를 확인하고 안전한 작업위치를 선정하여 작업 ③ 가능하면 변압기등 고압장비가 없는 위치로 설치되도록 감독관과 협의하여 작업 위치 변경 ④ 신호수는 작업자가 감전위험이 있는 위험한 위치로 움직이면 경고 신호를 보냄 / 감소대책: 정전작업 원칙 준수 및 절연장갑 및 공구, 활선보호구 착용 / 신호수의 역할 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (389,24,'2. 전기적 요인','39 화재폭발위험','UPS 활선작업 시 아크 발생으로 화재',1,3,'보통','① 인화성 물질을 제거하여 화재 예방 ② 소화기 비치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (390,24,'2. 전기적 요인','44 동물','하절기 야외 작업 중  벌쏘임',2,2,'보통','① 안전작업 절차 준수(작업반경 내 벌집 유무 확인)  ② 향이 짙은 향수 및 화장품 등 사용 자제  ③ 방충모자, 방추토시 착용 및 벌레 퇴치제 등을 활용  ④ 벌집을 건드렸을 때는 팔을 휘두르는 등 몸짓을 크게 하지 말고 머리를 감싼 채 20m이상 떨어진 곳으로 피함 / 감소대책: 벌 퇴치용 스프레이 지급 및 함체를 열기전에 내부 상황을 눈과 귀등 오감으로 파악 작업',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (391,24,'2. 전기적 요인','53 진동','전동드라이버 사용으로 인한 근골격계 질환 주의',1,2,'낮음','① 작업 전스트레칭 실시 ② 작업 중 충분한 휴식',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (392,24,'2. 전기적 요인','54 근로자실수(휴먼에러)','안전가이드 미준수 및  주의력 결핍으로 인한 안전사고 발생',2,3,'높음','① 반복적인 안전가이드 교육 및 불시 안전점검 ② 작업 중 충분한 휴식을 취하여 주의력 확보 / 감소대책: 작업안전가이드 준수 및 현장 점검 강화',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (393,24,'2. 전기적 요인','56 질식위험, 산소결핍','맨홀작업시 산소결핍에 의한 질식',2,3,'높음','① 안전보호구 착용 ② 환기팬으로 맨홀 내부 환기 ③  맨홀내부를 가스농도측정기로 측정하여 규정된 수치 이내에서만 맨홀 진입 ④ 구조용 삼각대를 설치하고 안전고리 체결 후 맨홀 진입 ⑤ 질식위험표지판,라바콘,콘걸이대 설치 ⑥ 감시인은 맨홀내부 작업자 상태가 어떤지 주기적으로 감시함 / 감소대책: 안전보호구 착용 및 작업전 산소 농도 측정, 환기및 구조 원칙 교육 및 감독',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (394,24,'2. 전기적 요인','57 중량물 취급작업','사다리차,고소작업대로,자재 운반 시 낙하물 발생',1,3,'보통','① 안전보호구 착용 ② 밧줄등으로 견고하게 고정하고 운반 ③ 표지판,라바콘을 설치하여 출입 통제 조치 ④ 신호수를 배치하여 보행자를 안전하게 유도',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (395,24,'2. 전기적 요인','58 반복작업','반복되는 작업으로 근골격계 질환 발생',2,2,'보통','작업전 스트레칭 실시  무리한 작업은 금하고 작업중에 충분한 휴식을 취함 / 감소대책: 무거운 물건은 공구를 사용하여 양중하는 것을 원칙으로 하고 장비 지급',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (396,24,'2. 전기적 요인','59 불안정한 작업자세','불안정하고 무리한 작업으로 근골격계 질환 발생',1,2,'낮음','① 작업전 스트레칭 실시 ② 적절한 자세로 무리하지 않도록 작업 함 ③ 작업 중 충분한 휴식을 취함',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (397,24,'2. 전기적 요인','510 작업(조작)도구','작업공구 취급 중 베임 및 찔림',2,1,'낮음','① 안전장갑(베임방지장갑), 긴팔 및 토시등 안전장구류 및 올바른 작업복 착용하여 피부 노출을 최소화',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (398,24,'6. 작업환경 요인','61 기후/고온/한랭/공기질','비,눈,안개,강풍등 악천후에 야외작업 시 미끄럽고 시야가 가려져 사고 발생',2,2,'보통','① 작업 중 충분한 휴식을 취함 ② 무리한 작업은 금지 ③위험경보 시 옥내작업 위주로 실시 / 감소대책: 무리한 야외 작업 금지',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (399,24,'6. 작업환경 요인','62 조명','맨홀안 작업시, 조도 미확보로 인한 시야 가림(부딪침, 찔림, 걸림)',1,2,'낮음','① 랜턴등의 조명으로 조도 확보',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (400,24,'6. 작업환경 요인','63 공간 및 이동통로','보행자 통로 미확보로 인한 사고 위험',1,2,'낮음','① 보행자 통로 확보 후 신호수의 보행자 유도',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (401,24,'6. 작업환경 요인','64 주변 근로자','보조작업자 및 신호수의 부주의로 인한 보행자 충돌',1,2,'낮음','① 안전 시설물(라바콘,콘 걸이대,콘라이트) 설치 ② 작업자/보조작업자간의 크로스체크',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (402,24,'6. 작업환경 요인','65 작업시간','8시간 이상 과도한 작업 진행으로 근골격게 질환 발생',1,2,'낮음','① 각 작업팀에게 적절한 작업을 배분하고 무리한 작업 금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (403,24,'6. 작업환경 요인','66 조직 안전문화','형식적이고 주먹구구식 안전관리로 인한 미흡한 안전활동으로 중대재해 발생',2,3,'높음','① 안전관리를 시스템화 하고  ② 전직원이 참여하도록 하는 KOSHA-MS / ISO45001 인증을 받고 ③ 실질적인 현장적용을 통하여 중대재해 방지 / 감소대책: 작업안전기이드 및 안전관리 시스템 교육',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (404,25,'1. 기계적 요인','11 협착위험 부분(감김, 끼임)','옥상 출입문등이 덮개형태일 경우 덮개를 여닫는중 손 끼임',1,2,'낮음','① 안전보호구 착용 ② 덮개를 여닫을시 설치된 손잡이를 사용하고 덮개가 완전히 열렸는지 확인 후 이동한다 ③ 계속해서 덮개를 통해 이동시에는 덮개를 열란 상태로 밧줄등으로 고정한다 ④ 사다리에 매달린채 덮개를 여닫을시에는 안전고리를 견고한 구조물(사다리 발판 최상단)에 체결한 후 덮개를 개폐한다',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (405,25,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','현장 이동시 벽이나 튀어나온 기존 구조물에 긁힘/베임',1,2,'낮음','① 안전보호구를 착용 ② 조도가 확보된 상태에서 이동하며, 이동 중 주위 돌출부위 등 위험요소를 확인하며 이동',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (406,25,'1. 기계적 요인','14 충돌위험 부분','동절기 작업장 이동시, 블랙아이스 도로로 주행 시 미끄러짐으로 인한 충돌',1,2,'낮음','① 평소보다 절반가량 서행 ② 급출발, 급가속, 급제동, 급회전 금지 ③ 적정 타이어 공기압 유지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (407,25,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대 공구함체 등을 밟고 자재하차, 승하차 시 미끄러짐',2,2,'보통','① 안전보호구를 착용 ② 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 사전에 작업 장애물 및 위험물 제거 완료 및 작업계획서 반영하고 팀간 공유',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (408,25,'1. 기계적 요인','16 추락위험 부분(개구부 등)','건물  고정사다리로 승하강시 추락',1,3,'보통','① 안전보호구 착용 ② 고정사다리 상태를 확인(녹슴,볼트풀림,파손여부,흔들림 등)후 승하강 ③ 승하강시 안전고리를 사다리 발판에 체결하면서 이동',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (409,25,'2. 전기적 요인','21 감전(안전전압초과)','고소작업차에서 발생되는 누설전류로 인한 감전',1,2,'낮음','① 활선경보기 착용 및 검전기로 누설전류 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (410,25,'6. 작업환경 요인','61 기후/고온/한랭/공기질','비, 눈, 바람 등 기상상황 중 야외 이동/작업 시 미끄러짐',2,2,'보통','① 이동경로에 바닥상태(결빙, 물 등) 확인 및 미끄럼방지조치 실시 ② 위험경보 시 옥내작업 위주로 실시, 무리한 옥외작업 금지 / 감소대책: 야외 작업에 대한 작업 중지',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (411,25,'1. 기계적 요인','11 협착위험 부분(감김, 끼임)','고소작업대 탑승하여 승하강 작업 시 탑승기 위에 위치한 기존 구조물 및 가로수 등에 머리가 끼임',2,2,'보통','① 안전보호구 착용 ② 기존 구조물과 가로수등의 위치를 파악하고 충분한 공간을 확보한 후 승하강 작업 ③ 승하강 작업에 협착위험이 있을 시 신호수가 작업자에게 경고 신호를 함 ③ 감독관 및 건물주와 협의하여 가능하면 장비위치를 장애물이 없는  위치로 선정 / 감소대책: 사전에 작업 공간 검토 및 위험요소를 제거하고 작업계획서 반영 및 팀원간 공유',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (412,25,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','케이블 절단 및 커넥터 연결시, 케이블에 손 찔림',1,2,'낮음','① 안전보호구 착용(절단방지장갑 및 팔토시 착용)으로 베날카로운 노출부에 의한 사고 예방',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (413,25,'1. 기계적 요인','13 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','경사로나 주차된 차량/장애물등때문이거나 이동하면서 작업을 하기 위해서 고소작업대 아웃트리거를 설치하지 않고 붐대를 펼칠 시 무게중심이 한쪽으로 쏠려 전도',2,3,'높음','① 작업전 아웃트리거 센서 정상작동 상태 확인 ② 월별 고소작업대 정기정검 (아웃트리거 센서) ③ 신호수(보조작업자)가 작업 전 아웃트리거 설치상태 재확인 ④ 교육 및 불시점검을 통해서 이동하면서 케이블 포설/철거 작업 금지 / 감소대책: 아웃트리거 센서 정기적 점검 및 안전조치 및 신호수의 역할로 아웃트리거 균형 상태 점검',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (414,25,'1. 기계적 요인','14 충돌위험 부분','고소작업대 작업 시 주행차량에 의한 충돌',2,3,'높음','① 표지판,라바콘,에어로봇을 설치하고 신호수를 추가 배치하여 주행 차량을 통제함 ② 표지판,라바콘,에어로봇을 충분히 이격하여 설치해서 운전자가 공사중임을 미리 인지할 수 있도록 함 ③ 주행자량이 지나갈 수 있는 공간을 확보하도록 고소작업대를 설치함 / 감소대책: 공사안내표지판 및 라바콘 등으로 차량이동 통제, 신호수의 안전한 장소 위치하여 신호 통제',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (415,25,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대 자재 하차시 공구함체를 밟다가 미끄러짐',2,2,'보통','① 안전보호구를 착용하고 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 안전보호구 성능 점검과 미끄럼 방지 테이프 부착',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (416,25,'1. 기계적 요인','16 추락위험 부분(개구부 등)','고소작업대 승하강 및 고소작업 시 작업대 바깥쪽으로 신체를 과하게 내밀고 작업 중 추락',2,3,'높음','① 안전보호구 착용 ② 탑승기 승하강시 탑승기에 안전고리를 체결하고,고소작업 시 조가선 및 구조물에 안전고리 체결 ③ 신체를 과하게  바깥으로 내밀지 않도록 탑승기나 붐대 위치를 조정하여 작업함 / 감소대책: 작업이 끝날때까지 안전보호구 착용 교육 및 점검',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (417,25,'2. 전기적 요인','21 감전(안전전압초과)','고소작업대  작업시 주변 변압기 접촉에 의한 감전',2,3,'높음','① 안전보호구 착용(활선감지기) ② 작업 전에 변압기 위치를 확인하고 안전한 작업위치를 선정하여 작업 ③ 가능하면 변압기등 고압장비가 없는 위치로 설치되도록 감독관과 협의하여 작업 위치 변경 ④ 신호수는 작업자가 감전위험이 있는 위험한 위치로 움직이면 경고 신호를 보냄 / 감소대책: 절연보호구 및 공구 지급하여 사용하게 하고 정전 작업 원칙 준수',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (418,25,'2. 전기적 요인','39 화재폭발위험','UPS 활선작업 시 아크 발생으로 화재',1,3,'보통','① 인화성 물질을 제거하여 화재 예방 ② 소화기 비치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (419,25,'2. 전기적 요인','44 동물','하절기 야외 작업 중  벌쏘임',2,2,'보통','① 안전작업 절차 준수(작업반경 내 벌집 유무 확인)  ② 향이 짙은 향수 및 화장품 등 사용 자제  ③ 방충모자, 방추토시 착용 및 벌레 퇴치제 등을 활용  ④ 벌집을 건드렸을 때는 팔을 휘두르는 등 몸짓을 크게 하지 말고 머리를 감싼 채 20m이상 떨어진 곳으로 피함 / 감소대책: 벌 퇴치용 스프레이 지급 및 함체를 열기전에 내부 상황을 눈과 귀등 오감으로 파악하여 안전작업',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (420,25,'2. 전기적 요인','53 진동','전동드라이버 사용으로 인한 근골격계 질환 주의',1,2,'낮음','① 작업 전스트레칭 실시 ② 작업 중 충분한 휴식',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (421,25,'2. 전기적 요인','54 근로자실수(휴먼에러)','안전가이드 미준수 및  주의력 결핍으로 인한 안전사고 발생',2,3,'높음','① 반복적인 안전가이드 교육 및 불시 안전점검 ② 작업 중 충분한 휴식을 취하여 주의력 확보 / 감소대책: 반복적인 교육 및 휴식제공',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (422,25,'2. 전기적 요인','56 질식위험, 산소결핍','맨홀작업시 산소결핍에 의한 질식',2,3,'높음','① 안전보호구 착용 ② 환기팬으로 맨홀 내부 환기 ③  맨홀내부를 가스농도측정기로 측정하여 규정된 수치 이내에서만 맨홀 진입 ④ 구조용 삼각대를 설치하고 안전고리 체결 후 맨홀 진입 ⑤ 질식위험표지판,라바콘,콘걸이대 설치 ⑥ 감시인은 맨홀내부 작업자 상태가 어떤지 주기적으로 감시함 / 감소대책: 안전보호구 착용 및 작업전 산소 농도 측정, 환기및 구조 원칙 교육 및 감독',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (423,25,'2. 전기적 요인','57 중량물 취급작업','사다리차,고소작업대로,자재 운반 시 낙하물 발생',1,3,'보통','① 안전보호구 착용 ② 밧줄등으로 견고하게 고정하고 운반 ③ 표지판,라바콘을 설치하여 출입 통제 조치 ④ 신호수를 배치하여 보행자를 안전하게 유도',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (424,25,'2. 전기적 요인','58 반복작업','반복되는 작업으로 근골격계 질환 발생',2,2,'보통','작업전 스트레칭 실시  무리한 작업은 금하고 작업중에 충분한 휴식을 취함 / 감소대책: 무리한 작업을 하지 않도록 교육 및 점검',1,3,'보통','관리감독자',1);
