INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (426,25,'2. 전기적 요인','510 작업(조작)도구','작업공구 취급 중 베임 및 찔림',2,1,'낮음','① 안전장갑(베임방지장갑), 긴팔 및 토시등 안전장구류 및 올바른 작업복 착용하여 피부 노출을 최소화',1,2,'낮음','관리감독자',1);
