INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (436,26,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대,포터 자재 하차시 공구함체등을 밟다가 미끄러짐',2,2,'보통','① 안전보호구를 착용하고 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지 / 감소대책: 미끄럼 방지 테이프 부착 및 2인1조 작업 시행',1,1,'낮음','관리감독자',1);
