INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (438,26,'1. 기계적 요인','11 협착위험 부분(감김, 끼임)','고소작업대 탑승하여 승하강 작업 시 답승기 위에 위치한 기존 구조물 및 가로수 등에 머리가 끼임',2,2,'보통','① 안전보호구 착용 ② 기존 구조물과 가로수등의 위치를 파악하고 충분한 공간을 확보한 후 승하강 작업 ③ 승하강 작업에 협착위험이 있을 시 신호수가 작업자에게 경고 신호를 함 ③ 감독관 및 건물주와 협의하여 가능하면 장비위치를 장애물이 없는  위치로 선정 / 감소대책: 작업전 장갑 착용 및 장비 사용에 따른 위험성 교육 시행',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (439,26,'1. 기계적 요인','12 위험한 표면 (절단, 베임, 긁힘)','CP주,IP주의 튀어나온 부분에 긁힘',1,2,'낮음','① 안전보호구 착용( 절단 방지 장갑 착용) ② 튀어나온 위치를 확인하고 함체 무리하게 작업 하지 않음 / 감소대책: 올바른 안전보호구 착용 및 작업자간 상호 의사소통, 올바른 양중 장비 사용 교육 및 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (440,26,'1. 기계적 요인','13 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','경사로나 주차된 차량/장애물등때문이거나 이동하면서 작업을 하기 위해서 고소작업대,오건차 아웃트리거를 설치하지 않고 붐대를 펼칠 시 무게중심이 한쪽으로 쏠려 전도 위험',2,3,'높음','① 작업전 아웃트리거 센서 정상작동 상태 확인 ② 월별 고소작업대 정기정검 (아웃트리거 센서) ③ 신호수(보조작업자)가 작업 전 아웃트리거 설치상태 재확인 ④ 교육 및 불시점검을 통해서 이동하면서 케이블 포설/철거 작업 금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (441,26,'1. 기계적 요인','14 충돌위험 부분','고소작업대,오거차 작업 시 주행차량에 의한 충돌',2,3,'높음','① 표지판,라바콘,에어로봇을 설치하고 신호수를 추가 배치하여 주행 차량을 통제함 ② 표지판,라바콘,에어로봇을 충분히 이격하여 설치해서 운전자가 공사중임을 미리 인지할 수 있도록 함 ③ 주행자량이 지나갈 수 있는 공간을 확보하도록 고소작업대를 설치함 / 감소대책: 라바콘 설치 및 안내표지판 설치, 신호수 역할 및 안전교육 실시 및 상시 점검',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (442,26,'1. 기계적 요인','15 넘어짐       (미끄러짐, 걸림, 헛디딤)','고소작업대,포터  자재 하역시 공구함체를 밟다가 미끄러짐',2,2,'보통','① 안전보호구를 착용하고 미끄럼방지테이프를 공구함체등 발을 닺는 부분에 부착하여 미끄럼 방지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (443,26,'1. 기계적 요인','16 추락위험 부분(개구부 등)','고소작업대 승하강 및 고소작업 시 작업대 바깥쪽으로 신체를 과하게 내밀고 작업 중 추락',2,3,'높음','① 안전보호구 착용 ② 탑승기 승하강시 탑승기에 안전고리를 체결하고,고소작업 시 조가선 및 구조물에 안전고리 체결 ③ 신체를 과하게  바깥으로 내밀지 않도록 탑승기나 붐대 위치를 조정하여 작업함',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (444,26,'2. 전기적 요인','21 감전(안전전압초과)','고소작업대,오거차 작업시 주변 변압기 접촉에 의한 감전 위험',2,3,'높음','① 안전보호구 착용(활선감지기) ② 작업 전에 변압기 위치를 확인하고 안전한 작업위치를 선정하여 작업 ③ 가능하면 변압기등 고압장비가 없는 위치로 설치되도록 감독관과 협의하여 작업 위치 변경 ④ 신호수는 작업자가 감전위험이 있는 위험한 위치로 움직이면 경고 신호를 보냄',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (445,26,'2. 전기적 요인','39 화재폭발위험','포크레인,함마드릴 터파기 작업중 지중매설되 가스관등을 터트려 폭발',1,3,'보통','① 도시가스공사 등에 신고하고 담당자 확인 후 터파기 진행 ② 포크레인 작업 시 감시인을 배치하여 혹시 매설되어 있을 수 있는 전선등을 확인하면서 터파기 작업',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (446,26,'2. 전기적 요인','44 동물','하절기 야외 작업 중  벌쏘임',2,2,'보통','① 안전작업 절차 준수(작업반경 내 벌집 유무 확인)  ② 향이 짙은 향수 및 화장품 등 사용 자제  ③ 방충모자, 방추토시 착용 및 벌레 퇴치제 등을 활용  ④ 벌집을 건드렸을 때는 팔을 휘두르는 등 몸짓을 크게 하지 말고 머리를 감싼 채 20m이상 떨어진 곳으로 피함 / 감소대책: 말벌퇴치 스프레이 지급 및 작업전 함체 내부를 소리나 눈으로 확인하고 작업하는 습관 교육',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (447,26,'2. 전기적 요인','53 진동','함마드릴 사용으로 인한 근골격계 질환 주의',1,2,'낮음','① 작업 전스트레칭 실시 ② 작업 중 충분한 휴식',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (448,26,'2. 전기적 요인','54 근로자실수(휴먼에러)','안전가이드 미준수 및  주의력 결핍으로 인한 안전사고 발생',2,3,'높음','① 반복적인 안전가이드 교육 및 불시 안전점검 ② 작업 중 충분한 휴식을 취하여 주의력 확보 / 감소대책: 충분한 휴식과 작업자간 의사소통을 통한 안전작업 교육 및 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (449,26,'2. 전기적 요인','57 중량물 취급작업','작업차량,고소작업대로,자재 운반 시 낙하물 발생',1,3,'보통','① 안전보호구 착용 ② 밧줄등으로 견고하게 고정하고 운반 ③ 표지판,라바콘을 설치하여 출입 통제 조치 ④ 신호수를 배치하여 보행자를 안전하게 유도',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (450,26,'2. 전기적 요인','58 반복작업','반복되는 작업으로 근골격계 질환 발생',2,2,'보통','작업전 스트레칭 실시  무리한 작업은 금하고 작업중에 충분한 휴식을 취함',1,2,'낮음','관리감독자',1);
