INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (453,26,'6. 작업환경 요인','61 기후/고온/한랭/공기질','비,눈,안개,강풍등 악천후에 야외작업 시 미끄럽고 시야가 가려져 사고 발생',2,2,'보통','① 작업 중 충분한 휴식을 취함 ② 무리한 작업은 금지 ③위험경보 시 옥내작업 위주로 실시 / 감소대책: 사전 일기예보를 파악하여 작업진행여부를 수시로 확인',1,2,'낮음','관리감독자',1);
