INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (474,27,'1. 기계적 요인','5-10 작업(조작)도구','사다리, 작업발판 사용중 추락',1,2,'낮음','① 사다리전도방지대 설치 및 사다라안전 지침 준수',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (475,27,'1. 기계적 요인','6-3 공간 및 이동통로','2단 적재 화물을 랙(RACK) 2단 이상에 보관 시 제품의 변형 및  편하중으로 인한 낙하사고 위험',1,3,'보통','① 팔레트 적재시 랩핑작업 작업 반경 내 접근 금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (476,27,'1. 기계적 요인','6-4 주변 근로자','지게차 하역작업을 위해 자재 운반차량 적재함에서 작업중인 근로자쪽으로 포크가 급하게 접근하여 추락',1,3,'보통','① 지게차 운전자는 신호수의 신호에 의해 작업토록 안전교육 실시 / 감소대책: 신호수의 역할 및 운전자간 신호요령 교육',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (477,28,'1. 기계적 요인','1-1 협착위험 부분(감김, 끼임)','날카로운 노출부(공사표지판)에 의한 베임, 긁힘 사고 위험',2,1,'낮음','① 안전장갑 및 팔토시 착용으로 베날카로운 노출부에 의한 사고 예방',1,2,'낮음','관리감독자',1);
