INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (502,28,'5. 작업특성 요인','6-3 공간 및 이동통로','트레이상부에서 케이블 포설에 따른 실족 및 추락',1,2,'낮음','① 트레이를 이동하며 작업할 경우 안전대 부착 설비를 설치, 조명확보, 서두름 금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (503,29,'1. 기계적 요인','1-1 협착위험 부분(감김, 끼임)','날카로운 노출부(공사표지판)에 의한 베임, 긁힘 사고 위험',2,1,'낮음','① 안전장갑 및 팔토시 착용으로 베날카로운 노출부에 의한 사고 예방',1,2,'낮음','관리감독자',1);
