INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (506,29,'1. 기계적 요인','1-4 충돌위험 부분','장마철 미끄러짐(수막현상)에 의한 추돌사고',2,2,'보통','① 타이어 공기압은 평소보다 10% 높게 설정 ② 우천 시에는 규정속도의 80%, 폭우 시에는 50%의 속도로 운행 ③ 안전거리 확보 하고, 브레이크 밟을 때는 여러 번에 걸쳐서 가볍게 밟기 / 감소대책: 타이어공기압 조절 및 운행시 감속, 급브레이크 금지',1,1,'낮음','관리감독자',1);
