INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (528,29,'5. 작업특성 요인','6-3 공간 및 이동통로','트레이상부에서 케이블 포설에 따른 실족 및 추락',1,2,'낮음','① 트레이를 이동하며 작업할 경우 안전대 부착 설비를 설치, 조명확보, 서두름 금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (529,30,'1. 기계적 요인','1-1 협착위험 부분(감김, 끼임)','날카로운 노출부(공사표지판)에 의한 베임, 긁힘 사고 위험',2,1,'낮음','① 안전장갑 및 팔토시 착용으로 베날카로운 노출부에 의한 사고 예방',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (530,30,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','작업장 이동중, 돌출부에 긁힘/베임',1,2,'낮음','① 이동중 육안으로 위험 요소 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (531,30,'1. 기계적 요인','1-3 기계(설비)의 낙하, 비래,        전복, 붕괴, 전도위험 부분','결속상태가 불량한 물건의 낙하·비래',2,1,'낮음','① 지정된,안전한 이동통로 확보 ② 도수 하역시 2인1조 OR 3인조 실시',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (532,30,'1. 기계적 요인','1-4 충돌위험 부분','장마철 미끄러짐(수막현상)에 의한 추돌사고',2,2,'보통','① 타이어 공기압은 평소보다 10% 높게 설정 ② 우천 시에는 규정속도의 80%, 폭우 시에는 50%의 속도로 운행 ③ 안전거리 확보 하고, 브레이크 밟을 때는 여러 번에 걸쳐서 가볍게 밟기 / 감소대책: 타이어 공기압 조절 및 감속운전, 급브레이크 방지 시스템 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (533,30,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','작업장주변 정리 정돈 상태 불량으로인한 발걸림사고 위험(부딪힘, 발목 골절)',2,1,'낮음','① 작업장주변 지반 및 발걸림 위해요소 육안 확인',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (534,30,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','트레이에 올라서 작업 중 트레이 붕괴에 의한 추락',1,2,'낮음','① 트레이에 포설 작업시 작업발판을 설치하여 작업 ② 트레이에 올라서 작업금지',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (535,30,'1. 기계적 요인','5-4 근로자실수(휴먼에러)','전방 시야미확보로 인한 추돌',1,2,'낮음','① 지정된,안전한 이동통로 확보 ② 도수 하역시 2인1조 OR 3인조 실시',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (536,30,'1. 기계적 요인','5-7 중량물 취급작업','무리한 힘의 사용으로 인한 근골격계 질환',2,1,'낮음','① 작업 전/중/후 스트레칭 실시 ② 중량물(5kg)에 대한 특별 조치 이행',1,2,'낮음','관리감독자',1);
