INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (539,30,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','동절기 근로자 이동 또는 작업 시 미끄러짐/넘어짐으로 인한 접질림, 발목염좌 등의 부상 위험',1,2,'낮음','① 이동통로에 쌓인 눈은 치우고, 결빙으로 인한 넘어질 위험이 있는지 확인 후 이동 ② 사다리, 작업발판 및 통로 결빙상태 확인 ③ 결빙 제거 및 미끄럼 방지 조치',1,2,'낮음','관리감독자',1);
