INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (544,30,'2. 전기적 요인','2-1 감전(안전전압초과)','전기 취급 작업시 전원 미차단, 절연용보호구 미착용으로 인한 감전 위험',1,2,'낮음','① 전기 취급 및 전기 노출 우려시 안전보호구(절연장갑, 활선접근경보기, 검전기) 착용 ② 노출된 충전부/전로 등이 있는 경우 절연용방호구로 절연 조치 ③ 작업대상 잔류전하 및 누설전류를 검전기를 이용해 확인',1,2,'낮음','관리감독자',1);
