INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (641,32,'5. 작업특성 요인','5-8 반복작업','자재(블록 및 철과류 등) 반복 운반으로 허리 및 신체부상',3,2,'높음','2인1조 나눠들기 도입 및 무리한 작업 지양',1,2,'낮음','관리감독자',1);
