INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (648,32,'6. 작업환경 요인','6-6 조직 안전문화','작업 전 TMB 및 건강체크 미실시로 작업자 건강이상 발생',2,1,'낮음','작업 전 안전교육 및 TBM 활동',1,2,'낮음','관리감독자',1);
