INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (650,33,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','준공검사 현장 현황 사전 측정을 위한 줄자 사용 시 줄자에 손가락 절단, 베임, 긁힘',1,1,'낮음','안전장갑 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (651,33,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','준공검사를 위하여 맨홀, 공동구 출입구를 열다가 손가락이나 발가락을 주의하지 못하여 절단되는 위험',2,3,'높음','안전보호구 착용(안전장갑, 안전화 등) 맨홀뚜껑이나 공동구 덮개 개방시 절대 활동부분에 손이나 발이 가지 않도록 교육 및 현장확인 맨홀개폐기 활용이 가능한 맨홀의 경우 맨홀개폐기 사용 / 감소대책: 안전화 착용 및 맨홀 뚜껑열기 도구 사용',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (652,33,'1. 기계적 요인','1-4 충돌위험 부분','준공검사를 위한 현장이동 중 차량 또는 보행자, 설비와 충돌',1,3,'보통','통행로 이동 및 주변 위험요소 확인 및 제거 후 통과 이동로 계획시 양호한 도로나 통행로 사전 판단 후 전파',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (653,33,'1. 기계적 요인','1-5 넘어짐       (미끄러짐, 걸림, 헛디딤)','준공검사를 위한 현장 이동차량 탑승시 넘어짐',1,2,'낮음','차량 탑승시 탑승발판 사용 및 안전화 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (654,33,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','각 작업현장의 준공검사 현장으로 이동간에 있을 수 있는 개구부에 의해 추락위험',1,3,'보통','해당공간 관계자를 통한 개구부 유무 확인 및 우회이동 특히 실내 작업현장의 경우 통행인원이 매우 적기때문에  개구부가 보호조치 안되있는 경우가 대부분이므로 각별히  주의토록 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (655,33,'2. 전기적 요인','2-1 감전(안전전압초과)','준공검사 대상 장소로 이동간에 노출되거나 노후된 선로의 전기 누전 및 활선 혼촉으로 인한 실시간 감전위험',1,3,'보통','전원 차단 후 준공검사, 절연용 보호구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (656,33,'2. 전기적 요인','2-1 감전(안전전압초과)','준공검사 대상 장소에 고인물을 제거하기 위한 양수기 설치 및 운용시 누전으로 인한 실시간 감전위험',1,3,'보통','전원 차단 후 준공검사, 절연용 보호구 착용 절연용 전선 및 접속기, 누전차단기 사용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (657,33,'3. 화학적 요인','3-1 가스','준공검사를 위한 맨홀 또는 공동구 출입구 개방시 내부의 가스에 의한 질식, 중독위험',2,2,'보통','맨홀 개방 후 충분한 환기조치 후 복합가스측정기 사용하여 이상유무 확인 후 작업준비에 필요한 절차 진행 / 감소대책: 뚜껑 열기전에 가스측정기로 측정하여 환기 및 안전장비 사용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (658,33,'3. 화학적 요인','3-1 가스','준공검사를 위한 맨홀 또는 공동구 내부 양수작업시 엔진형 양수기에서 발생된 매연으로 인한 질식, 중독위험',1,3,'보통','엔진형 양수기 배연기에 불연성 자바라를 연결하여 외부로 매연이 빠져나가도록 조치 입수구파이프를 길게 설치하여 본체 자체가 맨홀이나 공동구 외부에서 작동되도록 운용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (659,33,'3. 화학적 요인','3-4 액체','준공검사를 위한 맨홀 또는 공동구내 이동시나 지하철 선로 주변 배수로의 침출수나 고여있는 오염액체 접촉에 의한 피부질환 위험',1,3,'보통','접촉을 최대한 피할 수 있는 준공검사 준비절차 진행 (예. 함체를 손이아닌 도구를 이용해 외부로 꺼내기) 액체접촉을 완전히 차단할 수 있는 안전보호구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (660,33,'3. 화학적 요인','3-9 화재폭발위험','준공검사를 위하여 맨홀, 공동구 내부에 고인 물을 엔진형 양수기로 퍼내는 작업간 양수기 연료취급을 올바르게 하지 못하여 화재폭발위험',1,3,'보통','엔진형 양수기 연료보충시 반드시 시동을 끄고 보충 연료를 임의 인원이 취급할 수 없는 별도의 보관장소에 보관하고 특정인원만 취급토록 시스템화',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (661,33,'4. 생물학적 요인','4-1 병원성 미생물, 바이러스에        의한 감염','준공검사를 위한 맨홀 또는 공동구내 이동시나 지하철 선로 주변 배수로의 침출수나 고여있는 오염액체 접촉에 의한 각종 질환 위험(피부, 병원성 질환)',1,3,'보통','접촉을 최대한 피할 수 있는 준공검사 준비절차 진행 (예. 함체를 손이아닌 도구를 이용해 외부로 꺼내기) 액체접촉을 완전히 차단할 수 있는 안전보호구 착용 준공검사 종료 후 소독',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (662,33,'4. 생물학적 요인','5-4 근로자실수(휴먼에러)','준공검사간 숙련도 부족으로 우발적 상황대처가 부족하여 발생하는 다양한 상해위험',3,1,'보통','숙련자를 통한 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (663,33,'4. 생물학적 요인','5-7 중량물 취급작업','준공검사를 위한 맨홀뚜껑 개방이나 공동구 덮개 개방시  무리한 인력으로 개방하다 근골격계 질환 발생위험',1,3,'보통','맨홀개폐기 또는 쇠지렛대 사용하여 맨홀개방',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (664,33,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 저온에서 준공검사를 준비하여 한랭질환 발생위험',2,2,'보통','보온되는 작업복 착용, 장시간 준공검사 준비 지양 / 감소대책: 방한 작업복 지급 및 핫펙 지급',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (665,33,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 고온에서 준공검사를 준비하여 온열질환 발생위험',2,2,'보통','충분히 환기되는 작업복 착용, 장시간 준공검사 준비 지양,  충분한 수분 및 염분섭취 / 감소대책: 한낮 작업 지양 및 냉수 지급, 충분한 휴식 보장',1,3,'보통','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (666,33,'6. 작업환경 요인','6-2 조명','야간 준공검사 준비시 부족한 조도로 인하여 준비간 각종 설비시설 및 장비 등 다양한 물체와 협착, 충돌위험',1,3,'보통','주간에 준공검사 준비 및 준비시간확보 가능토록 검사계획 작업환경에 맞는 조명 운영, 안전장구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (667,33,'6. 작업환경 요인','6-2 조명','야간 준공검사 준비시 부족한 조도로 인하여 작업간 각종 설비시설 및 장비 등 다양한 물체와 절단, 베임, 긁힘 위험',1,3,'보통','주간에 준공검사 준비 및 준비시간확보 가능토록 검사계획 작업환경에 맞는 조명 운영, 안전장구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (668,33,'6. 작업환경 요인','6-3 공간 및 이동통로','준공검사 준비간 정리되지 않은 공간 및 이동통로로 인하여 넘어질 위험',2,2,'보통','준공검사 준비 장소(고소작업 차량, 창고 등) 사전 정리 후 준비 / 감소대책: 사전에 작업장 정리정돈 및 위험요소 제거',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (669,33,'6. 작업환경 요인','6-3 공간 및 이동통로','각 작업현장의 준공검사 현장으로 이동간에 있을 수 있는 개구부에 의해 추락위험',1,3,'보통','해당공간 관계자를 통한 개구부 유무 확인 및 우회이동 특히 실내 작업현장의 경우 통행인원이 매우 적기때문에  개구부가 보호조치 안되있는 경우가 대부분이므로 각별히  주의토록 교육',1,2,'낮음','관리감독자',1);
