INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (671,33,'1. 기계적 요인','1-1 협착위험 부분(감김, 끼임)','전주 함체나 설비확인을 위한 고소작업대 사용시 버켓탑승자가 붐대상승시 버켓과 선로, 설비사이에 협착되는 위험',2,3,'높음','붐대상승시 상승구간 확인 철저 및 사전 위험구간 회피 / 감소대책: 붐대 최대 상승구간 내 장애물 제거 또는 회피하여 작업',1,2,'낮음','관리감독자',1);
