INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (683,33,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','건물외벽 설비확인을 위한 고소작업대 사용시 버켓탑승자가버켓에서 추락할 위험',2,3,'높음','안전고리를 외벽에 체결할 수 있는 고정물에 체결 후 검사 / 감소대책: 상승시 및 상승후 작업시 안전고리 체결 원칙 준수',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (684,33,'1. 기계적 요인','1-6 추락위험 부분(개구부 등)','맨홀내부 함체나 공동구, 지하철 설비확인을 위하여 덮개개방이나 진입시 추락할 위험',1,3,'보통','맨홀개방시 주변에 통행을 제한할 수 있는 물품(라바콘, 입간판, 에어로봇 등) 및 감시인 운용 덮개 개방시 주의 간판 설치',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (685,33,'2. 전기적 요인','2-1 감전(안전전압초과)','준공검사시 작업장소의 전기 시설물 및 전기 누전 및 활선 혼촉으로 인한 실사간 감전위험',2,3,'높음','활선상태가 확인되는 경우 전원차단 가능한 작업환경이라면 전원 차단 후 준공검사 절연용 보호구 착용하 준공검사 준공검전 검전기 사용, 활선접근경보기 착용하 준공검사 / 감소대책: 정전작업 원칙 준수 및 절연 장갑 및 공구 사용, 검전기로 활선 및 여가전력 확인하여 조치 후 작업',1,1,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (686,33,'3. 화학적 요인','3-1 가스','준공검사시 맨홀, 공동구, 지하철 선로 내부의 가스에 의한  질식, 중독위험',2,3,'높음','충분한 환기조치 후 복합가스측정기 사용하여 이상유무 확인 후 작업준비에 필요한 절차 진행 지속적인 가스잔류로 인하여 환기조치가 의미가 없을 경우 송기마스크, 공기마스크 등을 착용 후 준공검사 진행 / 감소대책: 작업시작전 가스 측정기로 잔류가스 존재 확인하고 환기, 안전장비 및 안전보호구 지급, 구조원칙 숙지 여부 점검',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (687,33,'3. 화학적 요인','3-4 액체','준공검사시 맨홀 또는 공동구내, 지하철 선로 주변 배수로의 침출수나 고여있는 오염액체 접촉에 의한 피부질환 위험',1,3,'보통','준공검사 준비단계에서 최대한 접촉을 피할 수 있는 장소선정과 방법 계획 및 실행 (예. 함체를 손이아닌 도구를 이용해 외부로 꺼내기, 건조된 통행로 사용 등) 액체접촉을 완전히 차단할 수 있는 안전보호구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (688,33,'4. 생물학적 요인','4-1 병원성 미생물, 바이러스에        의한 감염','준공검사시 맨홀 또는 공동구내, 지하철 선로 주변 배수로의 침출수나 고여있는 오염액체 접촉에 의한 각종 질환 위험(피부, 병원성 질환)',1,3,'보통','준공검사 준비단계에서 최대한 접촉을 피할 수 있는 장소선정과 방법 계획 및 실행 (예. 함체를 손이아닌 도구를 이용해 외부로 꺼내기, 건조된 통행로 사용 등) 직접접촉을 완전히 차단할 수 있는 안전보호구 착용 준공검사 종료 후 소독조치 및 위생적 시설에서 세면, 샤워 등 실시',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (689,33,'4. 생물학적 요인','4-4 동물','다양한 장소에서 준공검사간 옥외나 옥내에서 서식하는 병원성 야생동물(쥐, 유해조류, 야생개 및 고양이 등)에 의하여  상해를 입을 위험',1,2,'낮음','준공검사 준비단계에서 검사현장 확인 철저 및 병원성 야생동물 식별시 사전 제거조치 검사자 사전 파상풍 주사 접종 피부노출 최대한 방지 및 안전보호구 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (690,33,'5. 작업특성 요인','5-1 소음','지하철에서 준공검사시 통행하는 지하철로 인해 발생하는 굉음으로 인한 난청설 질환 발생위험',3,2,'높음','귀덮개, 귀마개 등 소음방지 안전보호구 착용 지하철 운행시간대를 피해서 준공검사 일정 계획 / 감소대책: ks 인증 귀마게 지급 사용 점검',2,3,'높음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (691,33,'5. 작업특성 요인','5-4 근로자실수(휴먼에러)','검사자 숙련도 부족으로 우발적 상황대처가 부족하여 발생하는 위험',1,1,'낮음','숙련자를 통한 교육',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (692,33,'5. 작업특성 요인','5-6 질식위험, 산소결핍','맨홀, 공동구와 같이 출입구가 폐쇄될 경우 내부가 밀폐되어 질식이나 산소결핍이 발생할 위험',1,3,'보통','맨홀, 공동구 관련 준공검사시 출입구에 간판을 배치하여 내부에 인원이 있음을 인식시키거나 감시인 배치 맨홀, 공동구 진입전 내부 산소농도 및 유해가스 측정 후 위험여부 없는 것을 확인 후 진입',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (693,33,'5. 작업특성 요인','5-7 중량물 취급작업','준공검사시 사용하는 측정장비, 시험장비가 지나치게 무거워 운반간에 근골격계 질환 발생위험',2,2,'보통','인력운반시 무게를 고려하여 인원편성하 운반 운반간 주기적인 휴식실시 과도한 무게의 장비사용 예상시 장비사용하 운반 (지게차, 대차 등) / 감소대책: 과도한 무게 운반시 인력운반 금지 및 기계 사용, 작업자에게 충분한 휴식 제공',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (694,33,'5. 작업특성 요인','5-9 불안정한 작업자세','장시간 고정된 불안정한 자세로 준공검사를 실시하여  근골격계질환이 발생할 위험',1,1,'낮음','준공검사간 주기적인 스트레칭 불안정한 자세가 되지않도록 검사에 편안한 작업환경 구축 (각도, 높이 등)',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (695,33,'5. 작업특성 요인','5-9 불안정한 작업자세','준공검사 대상장소가 안정된 작업발판이 없는 구조로 인하여몸균형이 상실될 우려가 있어 추락이나 넘어짐이 발생할 위험',1,3,'보통','준공검사 준비단계에서 안정된 작업발판을 구비할 수 있는  조치(차량통행가능구간은 차량형 고소작업대 차량 이용) 안전보호구 착용 및 안전고리 체결점에 안전고리 체결 후  준공검사',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (696,33,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 저온에서 준공검사하여 한랭질환 발생위험',1,3,'보통','보온되는 작업복 착용, 장시간 검사 지양',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (697,33,'6. 작업환경 요인','6-1 기후/고온/한랭/공기질','장시간 고온에서 작업하여 온열질환 발생위험',1,3,'보통','충분히 환기되는 작업복 착용, 장시간 실사 지양, 충분한 수분 및 염분섭취',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (698,33,'6. 작업환경 요인','6-2 조명','야간 준공검사시 부족한 조도로 인하여 준비간 각종 설비시설 및 장비 등 다양한 물체와 협착, 충돌위험',1,3,'보통','주간에 준공검사 일정계획 및 협조 불가시에는 작업환경에 맞는 조명 운영, 안전장구류 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (699,33,'6. 작업환경 요인','6-2 조명','야간 준공검사시 부족한 조도로 인하여 작업간 각종 설비시설 및 장비 등 다양한 물체와 절단, 베임, 긁힘 위험',1,3,'보통','주간에 준공검사 일정계획 및 협조 불가시에는 작업환경에 맞는 조명 운영, 안전장구류 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (700,33,'6. 작업환경 요인','6-3 공간 및 이동통로','준공검사간 정리되지 않은 공간 및 이동통로로 인하여 넘어질 위험',3,1,'보통','준공검사 준비단계에서 사전 공간정리 후 검사',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (701,33,'6. 작업환경 요인','6-3 공간 및 이동통로','이동간 개구부로 인한 이동간 추락위험',1,3,'보통','불필요한 인원의 접근을 막고 우회할 수 있도록 조치 (라바콘, 안내간판, 에어로봇, 신호수 등)',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (702,33,'6. 작업환경 요인','6-4 주변 근로자','준공검사시 다수의 관계자가 다수의 주체 통제하에 참석하여 우발적인 상황 통제가 제한되어 다양한 상해 위험에 노출',1,2,'낮음','준공검사간 해당과정별 해당되는 인원만 현장에 위치하고 비해당되는 인원이 따로 집합해있는 장소 구비 중앙통제하 순서대로 준공검사 관련 절차진행',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (703,33,'6. 작업환경 요인','6-5 작업시간','장시간 검사로 인한 피로누적, 집중력 저하, 주의력저하',1,1,'낮음','장시간 검사지양, 충분한 휴식시간 확보',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (704,34,'1. 기계적 요인','1-1 협착위험 부분(감김, 끼임)','건물 입구 및 이동 주변 간 손가락 끼임',1,1,'낮음','안전장갑 착용',1,2,'낮음','관리감독자',1);
INSERT INTO risk_assessment_items (id,work_type_id,category,hazard,risk_factor,before_frequency,before_severity,before_risk_level,control_measures,after_frequency,after_severity,after_risk_level,responsible,is_active) VALUES (705,34,'1. 기계적 요인','1-2 위험한 표면 (절단, 베임, 긁힘)','건물 옥상 및 옥탑 주변 구조물 및 벽취부 사다리  표면 돌출 부분에 베임 및 긁힘',1,2,'낮음','절단 베임방지 안전장갑 착용',1,2,'낮음','관리감독자',1);
